/*srio_AssetAllExport*/
SELECT A.PRODUCT_ID,
       A.ASSET_POOL_ID,
       SUM(A.QUANTITY_ON_HAND_TOTAL),
       SUM(A.AVAILABLE_TO_PROMISE_TOTAL)
FROM ASSET A
WHERE A.OWNER_PARTY_ID = 'JKFD'
GROUP BY A.ASSET_POOL_ID;


/*srio_shipnoticeInfoCheck*/
SELECT SI.SHIPMENT_ID,
       SI.PRODUCT_ID,
       SI.QUANTITY,
       P.PRODUCT_NAME,
       S.STATUS_ID,
       S.PACKED_DATE,
       S.LAST_UPDATED_STAMP,
       S.SHIPMENT_TYPE_ENUM_ID,
       P.PSEUDO_ID,
       S.PRODUCT_STORE_ID,
       OH.DISPLAY_ID,
       SRS.CARRIER_PARTY_ID,
       SRS.SHIPMENT_METHOD_ENUM_ID,
       SRS.BILLING_WEIGHT,
       SPRS.TRACKING_CODE,
       SPRS.ESTIMATED_AMOUNT
FROM SHIPMENT_ITEM SI
         INNER JOIN PRODUCT P ON P.PRODUCT_ID = SI.PRODUCT_ID
         INNER JOIN SHIPMENT S ON S.SHIPMENT_ID = SI.SHIPMENT_ID
         INNER JOIN SHIPMENT_ITEM_SOURCE SIS ON SIS.SHIPMENT_ID = SI.SHIPMENT_ID
         INNER JOIN ORDER_HEADER OH ON OH.ORDER_ID = SIS.ORDER_ID
         LEFT JOIN SHIPMENT_ROUTE_SEGMENT SRS ON SRS.SHIPMENT_ID = SI.SHIPMENT_ID
         LEFT JOIN SHIPMENT_PACKAGE_ROUTE_SEG SPRS ON SPRS.SHIPMENT_ID = SI.SHIPMENT_ID
WHERE S.SHIPMENT_TYPE_ENUM_ID = 'SHPTPSALES'
  AND SI.SHIPMENT_ID IN ('3776242');

SELECT IS2.SHIPMENT_ID,
       IS2.ORDER_ID,
       IS2.PRODUCT_STORE_ID,
       IS2.SALES_CHANNEL_ENUM_ID,
       IS2.STATUS_ID,
       IS2.LAST_UPDATED_STAMP,
       OH.DISPLAY_ID
FROM INTEGRATION_SHIPMENT IS2
         INNER JOIN ORDER_HEADER OH ON OH.ORDER_ID = IS2.ORDER_ID
WHERE IS2.ORDER_ID IN (
    SELECT ORDER_ID
    FROM ORDER_HEADER OH
    WHERE OH.DISPLAY_ID IN (
                            'SA0004083-SH0004768', 'SA0004084-SH0004775', 'SA0004091-SH0004533', 'SA0004093-SH0004778',
                            'SA0004099-SH0004767', 'SA0004100-SH0004781', 'SA0004107-SH0004779', 'SA0004115-SH0004777',
                            'SA0004122-SH0004774', 'SA0004123-SH0004766', 'SA0004124-SH0004758', 'SA0004127-SH0004535',
                            'SA0004130-SH0004771', 'SA0006012-SH0004395', 'SA0006045-SH0004791', 'SA0006047-SH0004795',
                            'SA0006049-SH0004797', 'SA0006050-SH0004794', 'SA0006051-SH0004792', 'SA0006131-SH0004457',
                            'SA0006250-SH0004790', 'SA0006251-SH0004796'
        )
);



SELECT *
FROM INTEGRATION_SHIPMENT IS2
WHERE IS2.SALES_CHANNEL_ENUM_ID = 'SCSANRIO'
  AND STATUS_ID = 'ESNOTSTARTED'
  AND ORDER_ID IS NOT NULL
