/*srio_checkShipNoticeForOrders*/
SELECT OH.ORDER_ID,
       OH.ENTRY_DATE,
       OH.STATUS_ID,
       OH.PRODUCT_STORE_ID,
       OH.DISPLAY_ID,
       IS2.STATUS_ID
FROM ORDER_HEADER OH
         LEFT JOIN INTEGRATION_SHIPMENT IS2 ON IS2.ORDER_ID = OH.ORDER_ID
WHERE OH.PRODUCT_STORE_ID LIKE ('SRIO%')
  AND OH.STATUS_ID <> 'ORDERAPPROVED'
ORDER BY OH.ENTRY_DATE DESC;


/*asset_receipt*/
SELECT S.OTHER_PARTY_ORDER_ID,
       AR.PRODUCT_ID,
       P.PSEUDO_ID,
       AR.QUANTITY_ACCEPTED,
       PP.PRICE AS 'COST',
       AR.RECEIVED_DATE
FROM ASSET_RECEIPT AR
         INNER JOIN PRODUCT P ON P.PRODUCT_ID = AR.PRODUCT_ID
         LEFT JOIN PRODUCT_PRICE PP ON PP.PRODUCT_ID = P.PRODUCT_ID AND PP.PRICE_TYPE_ENUM_ID = 'PptAverage'
         INNER JOIN SHIPMENT S ON S.SHIPMENT_ID = AR.SHIPMENT_ID AND S.FROM_PARTY_ID = 'JUST'
WHERE S.OTHER_PARTY_ORDER_ID = 'J100002C';

/*asset_withReceipt*/
SELECT A.PRODUCT_ID,
       P.PSEUDO_ID,
       PP.PRICE AS 'COST',
       A.QUANTITY_ON_HAND_TOTAL,
       A.AVAILABLE_TO_PROMISE_TOTAL,
       A.STATUS_ID,
       AR.RECEIVED_DATE,
       AR.QUANTITY_ACCEPTED,
       S.OTHER_PARTY_ORDER_ID,
       A.FACILITY_ID,
       A.LOCATION_SEQ_ID
FROM ASSET A
         INNER JOIN PRODUCT P ON P.PRODUCT_ID = A.PRODUCT_ID
         LEFT JOIN PRODUCT_PRICE PP ON PP.PRODUCT_ID = P.PRODUCT_ID AND PP.PRICE_TYPE_ENUM_ID = 'PPTAVERAGE'
         LEFT JOIN ASSET_RECEIPT AR ON AR.ASSET_ID = A.ASSET_ID
         LEFT JOIN SHIPMENT S ON S.SHIPMENT_ID = AR.SHIPMENT_ID
WHERE A.OWNER_PARTY_ID = 'JUST'
  AND P.PSEUDO_ID = '003903-BLOSSOM-ONE SIZE';


/*findOverallocatedWithOH*/
SELECT OP.ORDER_ID,
       OP.ORDER_PART_SEQ_ID,
    OP.VENDOR_PARTY_ID,
       OP.FACILITY_ID,
       OI.PRODUCT_ID,
       SUM(OI.QUANTITY) AS 'ORDER QTY',
       ASUM.FACILITY_ID AS 'RESERVATION FACILITY',
       ASUM.QUANTITY_ON_HAND_TOTAL,
       ASUM.AVAILABLE_TO_PROMISE_TOTAL
FROM ORDER_ITEM OI
INNER JOIN ASSET_RESERVATION AR ON AR.ORDER_ID = OI.ORDER_ID AND AR.ORDER_ITEM_SEQ_ID = OI.ORDER_ITEM_SEQ_ID
LEFT JOIN (
    SELECT ASSET_ID,
           PRODUCT_ID,
           SUM(QUANTITY_ON_HAND_TOTAL)     AS QUANTITY_ON_HAND_TOTAL,
           SUM(AVAILABLE_TO_PROMISE_TOTAL) AS AVAILABLE_TO_PROMISE_TOTAL,
           FACILITY_ID
    FROM ASSET
    WHERE STATUS_ID = 'ASTAVAILABLE'
    GROUP BY PRODUCT_ID) ASUM ON ASUM.PRODUCT_ID = AR.PRODUCT_ID
INNER JOIN ORDER_PART OP ON OP.ORDER_ID = OI.ORDER_ID AND OP.ORDER_PART_SEQ_ID = OI.ORDER_PART_SEQ_ID
WHERE OP.VENDOR_PARTY_ID = 'BETA'
AND OP.STATUS_ID = 'ORDERAPPROVED'
AND OI.ITEM_TYPE_ENUM_ID = 'ITEMPRODUCT'
GROUP BY OP.ORDER_ID, OP.ORDER_PART_SEQ_ID, OP.VENDOR_PARTY_ID, OP.FACILITY_ID, OI.PRODUCT_ID, OI.QUANTITY, ASUM.FACILITY_ID;

/*find orders where the order part facility does not match the asset reservation*/
SELECT OI.ORDER_ID,
       OI.ORDER_PART_SEQ_ID,
       OI.ORDER_ITEM_SEQ_ID,
       OP.FACILITY_ID,
       A.FACILITY_ID
FROM ORDER_ITEM OI
INNER JOIN ASSET_RESERVATION AR ON AR.ORDER_ID = OI.ORDER_ID AND AR.ORDER_ITEM_SEQ_ID = OI.ORDER_ITEM_SEQ_ID
INNER JOIN ASSET A ON A.ASSET_ID = AR.ASSET_ID
INNER JOIN ORDER_PART OP ON OP.ORDER_ID = OI.ORDER_ID AND OP.ORDER_PART_SEQ_ID = OI.ORDER_PART_SEQ_ID
WHERE OP.VENDOR_PARTY_ID = 'BETA'
AND OP.STATUS_ID = 'ORDERAPPROVED'
AND OI.ITEM_TYPE_ENUM_ID = 'ITEMPRODUCT'
AND OP.FACILITY_ID <> A.FACILITY_ID;

####### REFUND QUEUE STUFF ######

/*refundQueue_error*/
SELECT IRR.RETURN_ID,
       IRR.PAYMENT_ID,
       IRR.ORDER_ID,
       IRR.PRODUCT_STORE_ID,
       IRR.STATUS_ID,
       IRR.CREATED_DATE,
       IRR.UPDATED_DATE,
       OH.DISPLAY_ID
FROM INTEGRATION_RETURN_REFUND IRR
         INNER JOIN ORDER_HEADER OH ON IRR.ORDER_ID = OH.ORDER_ID
WHERE IRR.STATUS_ID = 'ESOTHERERROR'
#AND WEEK(IRR.CREATED_DATE) = WEEK(NOW())-1
  AND IRR.CREATED_DATE > '2021-12-12'
  AND IRR.CREATED_DATE < '2022-01-02'
ORDER BY IRR.CREATED_DATE DESC;

/*refundqueue_pending*/
SELECT IRR.RETURN_ID,
       IRR.PAYMENT_ID,
       IRR.ORDER_ID,
       IRR.PRODUCT_STORE_ID,
       IRR.STATUS_ID,
       IRR.CREATED_DATE,
       IRR.UPDATED_DATE,
       OH.DISPLAY_ID
FROM INTEGRATION_RETURN_REFUND IRR
         INNER JOIN ORDER_HEADER OH ON IRR.ORDER_ID = OH.ORDER_ID
WHERE IRR.STATUS_ID = 'ESOTHERERROR'
  AND IRR.PRODUCT_STORE_ID NOT IN ('AQUA_SHOPIFY', 'BEBE_SHOPIFY', 'MUCK_SHOPIFY_CA')
ORDER BY IRR.CREATED_DATE DESC;

SELECT IRR.RETURN_ID,
       IRR.PAYMENT_ID,
       IRR.ORDER_ID,
       IRR.PRODUCT_STORE_ID,
       IRR.STATUS_ID,
       IRR.CREATED_DATE,
       IRR.UPDATED_DATE,
       OH.DISPLAY_ID
FROM INTEGRATION_RETURN_REFUND IRR
         INNER JOIN ORDER_HEADER OH ON IRR.ORDER_ID = OH.ORDER_ID
WHERE IRR.PRODUCT_STORE_ID IN ('BRNT_SHOPIFY')
ORDER BY IRR.CREATED_DATE DESC;

/*just_robotHospital*/
SELECT *
FROM SHIPMENT_ITEM_SOURCE SIS
         INNER JOIN ORDER_HEADER OH ON OH.ORDER_ID = SIS.ORDER_ID
         INNER JOIN SHIPMENT S ON S.SHIPMENT_ID = SIS.SHIPMENT_ID AND
                                  S.STATUS_ID NOT IN ('SHIPSHIPPED', 'SHIPDELIVERED', 'SHIPCANCELLED', 'SHIPPACKED')
