/*kk_refundCreditResponse*/
SELECT RH.DISPLAY_ID,
       PI.ID_VALUE,
       CONCAT(RH.DISPLAY_ID, '_', PI.ID_VALUE),
       RI.RETURN_RESPONSE_ENUM_ID,
       P.PAYMENT_ID
FROM RETURN_ITEM RI
         INNER JOIN RETURN_HEADER RH on RI.RETURN_ID = RH.RETURN_ID
         INNER JOIN PRODUCT_IDENTIFICATION PI
                    ON PI.PRODUCT_ID = RI.PRODUCT_ID AND PI.PRODUCT_ID_TYPE_ENUM_ID = 'PIDTSKU'
         INNER JOIN PAYMENT P ON P.PAYMENT_ID = RI.REFUND_PAYMENT_ID
WHERE RI.RETURN_RESPONSE_ENUM_ID = 'RRSPCREDIT'
  AND RI.ITEM_TYPE_ENUM_ID = 'ITEMPRODUCT'
  AND RH.DISPLAY_ID IN
      ('KK-126008');

SELECT RH.ENTRY_DATE,
       RH.DISPLAY_ID,
       PI.ID_VALUE,
       CONCAT(RH.DISPLAY_ID, '_', PI.ID_VALUE),
       RI.RETURN_RESPONSE_ENUM_ID,
       P.PAYMENT_ID
FROM RETURN_ITEM RI
         INNER JOIN RETURN_HEADER RH on RI.RETURN_ID = RH.RETURN_ID
         INNER JOIN PRODUCT_IDENTIFICATION PI
                    ON PI.PRODUCT_ID = RI.PRODUCT_ID AND PI.PRODUCT_ID_TYPE_ENUM_ID = 'PIDTSKU'
         INNER JOIN PAYMENT P ON P.PAYMENT_ID = RI.REFUND_PAYMENT_ID
WHERE RI.RETURN_RESPONSE_ENUM_ID = 'RRSPCREDIT'
  AND RI.ITEM_TYPE_ENUM_ID = 'ITEMPRODUCT'
  AND RH.ENTRY_DATE > '2022-01-21'
ORDER BY RH.ENTRY_DATE DESC;

/*ENCR-6896_chrmAgingOrdersReport*/
SELECT OI.ORDER_ID,
       OH.DISPLAY_ID,
       OH.PLACED_DATE,
       OP.STATUS_ID,
       OP.VENDOR_PARTY_ID,
       OP.FACILITY_ID,
       OI.PRODUCT_ID,
       P.PSEUDO_ID,
       OI.QUANTITY,
       QTYINSTOCK.QTYOHTTL,
       QTYINSTOCK.QTYATP
FROM ORDER_PART OP
INNER JOIN ORDER_ITEM OI ON OI.ORDER_PART_SEQ_ID = OP.ORDER_PART_SEQ_ID
    AND OI.ORDER_ID = OP.ORDER_ID
    AND OI.ITEM_TYPE_ENUM_ID = 'ITEMPRODUCT'
LEFT JOIN (SELECT A.PRODUCT_ID,
           A.STATUS_ID,
           SUM(A.QUANTITY_ON_HAND_TOTAL) AS 'QTYOHTTL',
           SUM(A.AVAILABLE_TO_PROMISE_TOTAL) AS 'QTYATP'
    FROM ASSET A
    WHERE A.OWNER_PARTY_ID = 'CHRM' AND A.FACILITY_ID = 'BOL_DC_FONTANA' AND A.STATUS_ID = 'ASTAVAILABLE'
    GROUP BY A.PRODUCT_ID) QTYINSTOCK ON QTYINSTOCK.PRODUCT_ID = OI.PRODUCT_ID
INNER JOIN ORDER_HEADER OH ON OH.ORDER_ID = OP.ORDER_ID
INNER JOIN PRODUCT P ON P.PRODUCT_ID = OI.PRODUCT_ID
WHERE OP.STATUS_ID = 'ORDERAPPROVED'
  AND OP.VENDOR_PARTY_ID = 'CHRM';


SELECT PI.ID_VALUE 'STYLE ID',
       PFCOLOR.ABBREV,
       P2.PSEUDO_ID,
       P2.PRODUCT_ID,
       P2.SALES_INTRODUCTION_DATE
FROM PRODUCT P2
         INNER JOIN PRODUCT_IDENTIFICATION PI
                    ON PI.PRODUCT_ID = P2.PRODUCT_ID AND PI.PRODUCT_ID_TYPE_ENUM_ID = 'PIDTSTYLEID'
         left JOIN (SELECT PFA.PRODUCT_ID,
                            PF.PRODUCT_FEATURE_TYPE_ENUM_ID,
                            PF.ABBREV,
                            PF.DESCRIPTION,
                            PF.OWNER_PARTY_ID
                     FROM PRODUCT_FEATURE_APPL PFA
                              INNER JOIN PRODUCT_FEATURE PF ON PF.PRODUCT_FEATURE_ID = PFA.PRODUCT_FEATURE_ID AND
                                                               PF.PRODUCT_FEATURE_TYPE_ENUM_ID = 'PFTCOLOR') PFCOLOR
                    ON PFCOLOR.PRODUCT_ID = P2.PRODUCT_ID
WHERE P2.OWNER_PARTY_ID = 'KK'
  AND P2.PRODUCT_TYPE_ENUM_ID = 'PTASSET'
AND P2.SALES_INTRODUCTION_DATE > '2022-02-02' AND P2.SALES_INTRODUCTION_DATE < '2022-02-03';

SELECT P.PSEUDO_ID, P.STATUS_ID, P.SALES_INTRODUCTION_DATE
FROM PRODUCT P WHERE P.OWNER_PARTY_ID = 'KK' AND P.PRODUCT_TYPE_ENUM_ID = 'PTVIRTUAL';


##brandedonline.externalstorefront.common.return.RefundServices.enqueueExport#ReturnRefund
SELECT RETH.DISPLAY_ID,
       RETH.ENTRY_DATE,
       RTIT.RETURN_ID,
       RTIT.PRODUCT_ID,
       RTIT.DESCRIPTION,
       RTIT.STATUS_ID,
       IRTR.PAYMENT_ID AS 'paymentId',
       IRTR.PRODUCT_STORE_ID,
       IRTR.STATUS_ID
FROM RETURN_ITEM RTIT
INNER JOIN RETURN_HEADER RETH ON RETH.RETURN_ID = RTIT.RETURN_ID
LEFT JOIN PAYMENT PAYM ON PAYM.PAYMENT_ID = RTIT.REFUND_PAYMENT_ID
LEFT JOIN INTEGRATION_RETURN_REFUND IRTR ON IRTR.RETURN_ID = RTIT.RETURN_ID
WHERE RETH.VENDOR_PARTY_ID = 'KK'
AND RTIT.ITEM_TYPE_ENUM_ID = 'ItemProduct'
AND RTIT.STATUS_ID = 'RETURNCOMPLETED'
AND PAYM.PAYMENT_ID IS NULL
AND RETH.ENTRY_DATE > '2022-09-01 00:00'
ORDER BY RETH.ENTRY_DATE DESC;


/*
 check weights of outgoing shipments
 */
SELECT OH.ORDER_ID,
       OH.DISPLAY_ID,
       OH.PLACED_DATE,
       P.PSEUDO_ID,
       SP.SHIPMENT_ID,
       SP.SHIPMENT_PACKAGE_SEQ_ID,
       SPRS.TRACKING_CODE,
       SPRS.ACTUAL_AMOUNT,
       SPRS.INSURED_AMOUNT,
       SPRS.INSURANCE_AMOUNT,
       SPRS.BASE_AMOUNT,
       SPRS.ESTIMATED_AMOUNT,
       SP.WEIGHT,
       SP.WEIGHT_UOM_ID,
       SBT.PSEUDO_ID
FROM SHIPMENT_PACKAGE SP
INNER JOIN SHIPMENT_ITEM_SOURCE SIS ON SIS.SHIPMENT_ID = SP.SHIPMENT_ID
INNER JOIN ORDER_ITEM OI ON OI.ORDER_ID = SIS.ORDER_ID AND OI.ORDER_ITEM_SEQ_ID = SIS.ORDER_ITEM_SEQ_ID AND OI.ITEM_TYPE_ENUM_ID = 'ITEMPRODUCT'
INNER JOIN ORDER_PART OP ON OP.ORDER_ID = OI.ORDER_ID AND OP.ORDER_PART_SEQ_ID = OI.ORDER_PART_SEQ_ID
INNER JOIN ORDER_HEADER OH ON OH.ORDER_ID = OP.ORDER_ID
INNER JOIN SHIPMENT_PACKAGE_ROUTE_SEG SPRS ON SPRS.SHIPMENT_ID = SP.SHIPMENT_ID AND SPRS.SHIPMENT_PACKAGE_SEQ_ID = SP.SHIPMENT_PACKAGE_SEQ_ID
INNER JOIN SHIPMENT_BOX_TYPE SBT ON SBT.SHIPMENT_BOX_TYPE_ID = SP.SHIPMENT_BOX_TYPE_ID
INNER JOIN PRODUCT P ON P.PRODUCT_ID = OI.PRODUCT_ID
WHERE OH.PRODUCT_STORE_ID = 'SG_101174'
AND P.PSEUDO_ID NOT IN ('WARRANTY-1YR')
ORDER BY OH.ORDER_ID,SP.SHIPMENT_ID,SP.SHIPMENT_PACKAGE_SEQ_ID;

