-- mantle.product.AssetServices.move#Asset
select a.ASSET_ID as 'assetId',
       'NOG_DC_COMPTON' as 'facilityId',
       a.LOCATION_SEQ_ID as 'locationSeqId',
       a.ASSET_POOL_ID as 'assetPoolId',
       a.CONTAINER_ID as 'containerId',
       a.QUANTITY_ON_HAND_TOTAL as 'quantity',
       a.FACILITY_ID as '[delete] current facility', -- delete these lines before upload
        fl.LOCATION_SEQ_ID as '[delete] new facility location',
        fl.LOCATION_TYPE_ENUM_ID as '[delete] location type',
        a.STATUS_ID as '[delete] status id'
from ASSET a
left join FACILITY_LOCATION fl on fl.LOCATION_SEQ_ID = a.LOCATION_SEQ_ID and fl.FACILITY_ID = 'nog_dc_compton'
where a.OWNER_PARTY_ID = '3423267' -- update this for client
and a.FACILITY_ID in ('bol_dc_fontana')
and a.QUANTITY_ON_HAND_TOTAL > 0
and a.LOCATION_SEQ_ID not in ('Dmg-Quar-Loc-01','Damages-Bebe','Damages-KJKJ','Damages-HardTail','Damages-Alloy','Damages-KK','RTN-DAM-BIN-01','Damages-HH');


-- mantle.shipment.ShipmentServices.update#ShipmentAndRouteSegment
select s.SHIPMENT_ID as 'shipmentId',
       srs.SHIPMENT_ROUTE_SEGMENT_SEQ_ID as 'shipmentRouteSegmentSeqId',
       'NOG_DC_COMPTON' as 'originFacilityId',
       srs.ORIGIN_FACILITY_ID as '[delete] current facility'
from SHIPMENT s
inner join SHIPMENT_ROUTE_SEGMENT srs on srs.SHIPMENT_ID = s.SHIPMENT_ID and srs.ORIGIN_FACILITY_ID not in ('nog_dc_compton','NOG_DC_PITTSBURGH_FACILITY')
where s.PRODUCT_STORE_ID like ('%katy%')
and s.STATUS_ID not in ('shipshipped','shipdelivered','shipcancelled')
and s.SHIPMENT_TYPE_ENUM_ID not in ('shptpsalesreturn')
order by s.ENTRY_DATE desc;

-- mantle.order.OrderServices.update#OrderPart
select
    op.ORDER_ID as 'orderId',
    op.ORDER_PART_SEQ_ID as 'orderPartSeqId',
    'KCNY_EASTMAN_BULK' as 'vendorPartyId'
from ORDER_PART op
where op.ORDER_ID in ('5418339','5418361','5418360','5418090');

/*
 find duplicate UPCs ENCR-8269
 */
SELECT P.PRODUCT_ID,
       P.PRODUCT_NAME,
       P.PSEUDO_ID AS 'SKU1',
       P.OWNER_PARTY_ID AS 'P1 OWNER',
       PI.PRODUCT_ID AS 'PID1',
       PI.ID_VALUE AS 'UPC1',
       AST1.QOHTTL AS 'P1 QOH TTL',
       P2.OWNER_PARTY_ID AS 'P2 OWNER',
       P2.PSEUDO_ID AS 'SKU2',
       PI2.PRODUCT_ID AS 'PID2',
       PI2.ID_VALUE AS 'UPC2',
       AST2.QOHTTL2 AS 'P2 QOH TTL'
FROM PRODUCT P
INNER JOIN PRODUCT_IDENTIFICATION PI ON PI.PRODUCT_ID = P.PRODUCT_ID AND PI.PRODUCT_ID_TYPE_ENUM_ID = 'PIDTUPCA'
INNER JOIN PRODUCT_IDENTIFICATION PI2 ON PI2.ID_VALUE = PI.ID_VALUE AND PI2.PRODUCT_ID <> PI.PRODUCT_ID
INNER JOIN PRODUCT P2 ON P2.PRODUCT_ID = PI2.PRODUCT_ID AND P2.PRODUCT_TYPE_ENUM_ID = 'PTASSET'
LEFT JOIN (
    SELECT
        A.PRODUCT_ID,
        SUM(A.QUANTITY_ON_HAND_TOTAL) AS 'QOHTTL'
    FROM ASSET A
    GROUP BY A.PRODUCT_ID
) AST1 ON AST1.PRODUCT_ID = P.PRODUCT_ID
LEFT JOIN (
    SELECT
        A2.PRODUCT_ID,
        SUM(A2.QUANTITY_ON_HAND_TOTAL) AS 'QOHTTL2'
    FROM ASSET A2
    GROUP BY A2.PRODUCT_ID
) AST2 ON AST2.PRODUCT_ID = P2.PRODUCT_ID
WHERE P.OWNER_PARTY_ID IN ('BNYC')
AND P.PRODUCT_TYPE_ENUM_ID = 'PTASSET';

/*
 help LT do inventory comparisons for pittsburgh facility
 existing clients:
 - kcny DONE lt
 - modc DONE
 - aly
 - bebe - lt
 - beta
 - frye/fryw
 - hrly
 - katy
 */

select a.OWNER_PARTY_ID,
       sum(a.QUANTITY_ON_HAND_TOTAL)
from ASSET a
where a.FACILITY_ID = 'nog_dc_pittsburgh_facility'
group by a.OWNER_PARTY_ID;

SELECT
	P.PSEUDO_ID,
	P.PRODUCT_ID,
	SUM( IF(A.STATUS_ID = 'AstAvailable', AVAILABLE_TO_PROMISE_TOTAL, 0)) AS ATP_QUANTITY_AVAILALBE,
	SUM( IF(A.STATUS_ID = 'AstAvailable', QUANTITY_ON_HAND_TOTAL, 0)) AS QOH_AVAILABLE,
	SUM( IF(A.STATUS_ID = 'AstOnHold', AVAILABLE_TO_PROMISE_TOTAL, 0)) AS ATP_QUANTITY_HOLD,
	SUM( IF(A.STATUS_ID = 'AstOnHold', QUANTITY_ON_HAND_TOTAL, 0)) AS QOH_QUANTITY_HOLD,
	SUM( IF(A.STATUS_ID <> 'AstOnHold' && A.STATUS_ID <> 'AstAvailable', AVAILABLE_TO_PROMISE_TOTAL, 0)) AS ATP_QUANTITY_OTHER,
	SUM( IF(A.STATUS_ID <> 'AstOnHold' && A.STATUS_ID <> 'AstAvailable', QUANTITY_ON_HAND_TOTAL, 0)) AS QOH_QUANTITY_OTHER
FROM
	ASSET A
INNER JOIN PRODUCT P ON P.PRODUCT_ID = A.PRODUCT_ID
WHERE
	A.QUANTITY_ON_HAND_TOTAL > 0.0 AND P.OWNER_PARTY_ID = 'hrly'
AND A.FACILITY_ID NOT IN ('HRLY_FACILITY')
GROUP BY P.PSEUDO_ID, P.PRODUCT_ID;


SELECT
    OP.VENDOR_PARTY_ID,
    SUM(CASE WHEN DATEDIFF(CURDATE(),DATE(OH.ENTRY_DATE)) < 1
        THEN 1
        ELSE 0 END) AS '< 1 DAY',
    SUM(CASE WHEN DATEDIFF(CURDATE(),DATE(OH.ENTRY_DATE)) BETWEEN 2 AND 3
        THEN 1
        ELSE 0 END) AS '2 - 3 DAYS',
    SUM(CASE WHEN DATEDIFF(CURDATE(),DATE(OH.ENTRY_DATE)) BETWEEN 4 AND 7
        THEN 1
        ELSE 0 END) AS '4 - 7 DAYS',
    SUM(CASE WHEN DATEDIFF(CURDATE(),DATE(OH.ENTRY_DATE)) BETWEEN 8 AND 14
        THEN 1
        ELSE 0 END) AS '8 - 14 DAYS',
    SUM(CASE WHEN DATEDIFF(CURDATE(),DATE(OH.ENTRY_DATE)) BETWEEN 15 AND 30
        THEN 1
        ELSE 0 END) AS '15 - 30 DAYS',
    SUM(CASE WHEN DATEDIFF(CURDATE(),DATE(OH.ENTRY_DATE)) > 30
        THEN 1
        ELSE 0 END) AS '> 30 DAYS'
FROM ORDER_HEADER OH
INNER JOIN ORDER_PART OP ON OP.ORDER_ID = OH.ORDER_ID
INNER JOIN FACILITY F ON F.FACILITY_ID = OP.FACILITY_ID AND F.OWNER_PARTY_ID = 'BOL'
WHERE OH.STATUS_ID NOT IN ('ORDERCANCELLED','ORDERCOMPLETED')
GROUP BY OP.VENDOR_PARTY_ID;


SELECT A.FACILITY_ID as 'DC',
       A.OWNER_PARTY_ID as 'Brand',
       PI.ID_VALUE as 'SKU',
       SUM(A.AVAILABLE_TO_PROMISE_TOTAL) as 'Quantity'
FROM ASSET A
INNER JOIN PRODUCT P ON P.PRODUCT_ID = A.PRODUCT_ID
INNER JOIN PRODUCT_IDENTIFICATION PI ON PI.PRODUCT_ID = P.PRODUCT_ID
    AND PI.PRODUCT_ID_TYPE_ENUM_ID = 'PIDTSKU'
WHERE P.OWNER_PARTY_ID = 'JUST'
and A.AVAILABLE_TO_PROMISE_TOTAL >= 0
and A.FACILITY_ID = 'BOL_DC_FONTANA_2'
/*and A.FACILITY_ID IN ('BOL_DC_FONTANA','BOL_DC_FONTANA_2','NOG_DC_PITTSBURGH_FACILITY','NOG_DC_COMPTON')*/
GROUP BY A.FACILITY_ID,A.PRODUCT_ID
ORDER BY PI.ID_VALUE;

/*
indexOrdersForSmartShip_
brandedonline.search.SearchServices.index#DataDocuments
 */
SELECT 'NoginOrders' as 'dataDocumentId',
       concat('orderId=',OH.ORDER_ID) as 'dataDocumentFieldFilter'
FROM ORDER_HEADER OH
WHERE OH.PRODUCT_STORE_ID IN ('SG_101224','SG_101174') -- SG_101224 (Chopra); SG_101174 (Wing); SG_100918 (Gelblaster)
AND ENTRY_DATE BETWEEN '2023-04-11 00:00' AND '2023-04-18 00:00';


/*
 arash shipment outgoing
 */
SELECT *
FROM SHIPMENT S
INNER JOIN SHIPMENT_ROUTE_SEGMENT SRS ON SRS.SHIPMENT_ID = S.SHIPMENT_ID
WHERE SRS.ORIGIN_FACILITY_ID IN ('NOG_DC_COMPTON','NOG_DC_PITTSBURGH_FACILITY','BOL_DC_FONTANA_2','BOL_DC_FONTANA')
AND S.ENTRY_DATE > '2022-01-01 00:00'
AND S.SHIPMENT_TYPE_ENUM_ID = 'ShpTpSales'
AND S.STATUS_ID <> 'ShipCancelled';

SELECT COUNT(DISTINCT S.SHIPMENT_ID),
       S.SHIPMENT_TYPE_ENUM_ID,
       S.STATUS_ID,
       SRS.ORIGIN_FACILITY_ID
FROM SHIPMENT S
INNER JOIN SHIPMENT_ROUTE_SEGMENT SRS ON SRS.SHIPMENT_ID = S.SHIPMENT_ID
WHERE SRS.ORIGIN_FACILITY_ID IN ('NOG_DC_COMPTON','NOG_DC_PITTSBURGH_FACILITY','BOL_DC_FONTANA_2','BOL_DC_FONTANA')
AND S.ENTRY_DATE > '2022-01-01 00:00'
GROUP BY S.SHIPMENT_TYPE_ENUM_ID,S.STATUS_ID;

SELECT S.ENTRY_DATE,
    S.SHIPMENT_ID,
       S.STATUS_ID,
        P.OWNER_PARTY_ID AS 'productOwnerPartyId',
       P.PRODUCT_ID AS 'encoreProductId',
       P.PSEUDO_ID AS 'SKU',
       PIUPCA.ID_VALUE AS 'UPC',
       SI.QUANTITY,
       SI.ORIGINAL_QUANTITY,
       S.SHIP_BEFORE_DATE,
       S.ESTIMATED_ARRIVAL_DATE,
       OI.REQUIRED_BY_DATE,
       OP.SHIP_BEFORE_DATE,
       OP.SHIP_AFTER_DATE
FROM SHIPMENT S
INNER JOIN SHIPMENT_ITEM SI ON SI.SHIPMENT_ID = S.SHIPMENT_ID
INNER JOIN PRODUCT P ON P.PRODUCT_ID = SI.PRODUCT_ID
INNER JOIN PRODUCT_IDENTIFICATION PIUPCA ON PIUPCA.PRODUCT_ID = P.PRODUCT_ID AND PIUPCA.PRODUCT_ID_TYPE_ENUM_ID = 'PIDTUPCA'
LEFT JOIN SHIPMENT_ITEM_SOURCE SIS ON SIS.SHIPMENT_ID = SI.SHIPMENT_ID AND SIS.PRODUCT_ID = SI.PRODUCT_ID
LEFT JOIN ORDER_ITEM OI ON OI.ORDER_ID = SIS.ORDER_ID AND OI.ORDER_ITEM_SEQ_ID = SIS.ORDER_ITEM_SEQ_ID
LEFT JOIN ORDER_PART OP ON OP.ORDER_ID = OI.ORDER_ID AND OP.ORDER_PART_SEQ_ID = OI.ORDER_PART_SEQ_ID
WHERE S.SHIPMENT_TYPE_ENUM_ID IN ('SHPTPINCOMING','ShpTpPurchase')
AND S.ENTRY_DATE > '2022-01-01 00:00'
ORDER BY S.ENTRY_DATE DESC;


/*
 receive from old to new product
 */
-- mantle.product.AssetServices.receive#Asset
SELECT A.ASSET_ID AS 'assetId',
       P.PSEUDO_ID AS 'pseudoId [delete]',
       A.STATUS_ID AS 'statusId',
       A.OWNER_PARTY_ID AS 'ownerPartyId',
       A.ASSET_POOL_ID AS 'assetPoolId',
       A.PRODUCT_ID AS 'productId [update]',
       A.RECEIVED_DATE AS 'receivedDate',
       A.FACILITY_ID AS 'facilityId',
       A.LOCATION_SEQ_ID AS 'locationSeqId',
       A.CONTAINER_ID AS 'containerId', -- delete if empty
       A.LOT_ID AS 'lotId',
       A.QUANTITY_ON_HAND_TOTAL AS 'quantity'
FROM ASSET A
INNER JOIN PRODUCT P ON P.PRODUCT_ID = A.PRODUCT_ID
WHERE A.PRODUCT_ID IN (
    '1764896','1764902','1764903','1764897','1827906','1763046','1763323','1801202','1918519'
    )
AND A.QUANTITY_ON_HAND_TOTAL > 0;

SELECT SI.SHIPMENT_ID,
       SI.PRODUCT_ID,
       P.PSEUDO_ID,
       SI.QUANTITY,
       SUM(AR.QUANTITY_ACCEPTED)
FROM SHIPMENT_ITEM SI
LEFT JOIN ASSET_RECEIPT AR ON AR.SHIPMENT_ID = SI.SHIPMENT_ID AND AR.PRODUCT_ID = SI.PRODUCT_ID
INNER JOIN PRODUCT P ON P.PRODUCT_ID = SI.PRODUCT_ID
WHERE SI.SHIPMENT_ID = '4564216'
GROUP BY SI.SHIPMENT_ID, SI.PRODUCT_ID, P.PSEUDO_ID, SI.QUANTITY;

/*
 LT
 */
SELECT
	   *
       FROM RETURN_HEADER RH
INNER JOIN RETURN_ITEM RI ON RI.RETURN_ID = RH.RETURN_ID
INNER JOIN SHIPMENT_ITEM_SOURCE SIS ON SIS.RETURN_ID = RI.RETURN_ID AND SIS.RETURN_ITEM_SEQ_ID = RI.RETURN_ITEM_SEQ_ID
INNER JOIN SHIPMENT_ITEM SI ON SI.SHIPMENT_ID = SIS.SHIPMENT_ID AND SI.PRODUCT_ID = SIS.PRODUCT_ID
INNER JOIN ASSET_RECEIPT AR ON AR.SHIPMENT_ID = SIS.SHIPMENT_ID AND AR.RETURN_ID = SIS.RETURN_ID AND AR.RETURN_ITEM_SEQ_ID = SIS.RETURN_ITEM_SEQ_ID
INNER JOIN PRODUCT P ON P.PRODUCT_ID = SI.PRODUCT_ID
INNER JOIN PRODUCT_IDENTIFICATION PIUPCA ON PIUPCA.PRODUCT_ID = P.PRODUCT_ID AND PIUPCA.PRODUCT_ID_TYPE_ENUM_ID = 'PIDTUPCA'
INNER JOIN ORDER_ITEM OI ON OI.ORDER_ID = RI.ORDER_ID AND OI.ORDER_ITEM_SEQ_ID = RI.ORDER_ITEM_SEQ_ID
INNER JOIN ORDER_PART OP ON OP.ORDER_ID = OI.ORDER_ID AND OP.ORDER_PART_SEQ_ID = OI.ORDER_PART_SEQ_ID
INNER JOIN POSTAL_ADDRESS CUST_PA ON CUST_PA.CONTACT_MECH_ID = OP.POSTAL_CONTACT_MECH_ID
LEFT JOIN FACILITY_CONTACT_MECH FCM ON FCM.FACILITY_ID = RH.FACILITY_ID AND FCM.CONTACT_MECH_PURPOSE_ID = 'POSTALPRIMARY' AND FCM.THRU_DATE IS NULL
LEFT JOIN POSTAL_ADDRESS WHSE_PA ON WHSE_PA.CONTACT_MECH_ID = FCM.CONTACT_MECH_ID
LEFT JOIN SHIPMENT_PACKAGE_ROUTE_SEG SPRS ON SPRS.SHIPMENT_ID = SI.SHIPMENT_ID
LEFT JOIN SHIPMENT_ROUTE_SEGMENT SRS ON SRS.SHIPMENT_ID=SI.SHIPMENT_ID
WHERE RH.ENTRY_DATE BETWEEN '2021-06-01 00:00:00' AND '2023-01-01 00:00:00' AND RH.RETURN_ID='913659'
ORDER BY RH.ENTRY_DATE DESC;



/*
 ENCR-8533 warehouse pittsburgh locations
 change all return locations to receiving (automatic on hold status)
 change all receiving locations to bulk (automatic available status)
 */

-- step 1, find all return staging locations
SELECT *
FROM FACILITY_LOCATION FL
WHERE FL.FACILITY_ID = 'NOG_DC_PITTSBURGH_FACILITY'
AND FL.LOCATION_SEQ_ID LIKE ('%-RET-%')
AND FL.LOCATION_TYPE_ENUM_ID = 'FLTSTAGING';

-- step 2, find all receiving locations
SELECT *
FROM FACILITY_LOCATION FL
WHERE FL.FACILITY_ID = 'NOG_DC_PITTSBURGH_FACILITY'
AND FL.LOCATION_TYPE_ENUM_ID = 'FLTRECEIVING'
AND FL.LOCATION_SEQ_ID LIKE ('%-RCV-%');


/*
 Get an upload ready file for Whiplash
 */
SELECT OH.PRODUCT_STORE_ID as 'ProductStoreId',
        CONCAT(OH.DISPLAY_ID,'-',OP.ORDER_PART_SEQ_ID) as 'OrderNumber',
       OH.DISPLAY_ID as 'ShipId',
       OP.CARRIER_PARTY_ID as 'ShippingMethod',
       E.DESCRIPTION as 'ShippingType',
       '' as 'TrackingNumber',
       '1' as 'OrderWeight',
       '' as 'TotalCharge',
       '1' as 'NoOfBox',
       OI.ORDER_ITEM_SEQ_ID as 'LineNumber',
       P.PSEUDO_ID as 'ProductId',
       '' as 'Quantity'
FROM ORDER_HEADER OH
INNER JOIN ORDER_ITEM OI ON OI.ORDER_ID = OH.ORDER_ID AND OI.ITEM_TYPE_ENUM_ID = 'ItemProduct'
INNER JOIN ORDER_PART OP ON OP.ORDER_ID = OI.ORDER_ID AND OP.ORDER_PART_SEQ_ID = OI.ORDER_PART_SEQ_ID
INNER JOIN PRODUCT P ON P.PRODUCT_ID = OI.PRODUCT_ID
LEFT JOIN ENUMERATION E ON E.ENUM_ID = OP.SHIPMENT_METHOD_ENUM_ID
WHERE OP.FACILITY_ID = 'BETA_WHIPLASH_FACILITY';




SELECT S.PRODUCT_STORE_ID,
       SRS.ORIGIN_FACILITY_ID,
       SUM(SI.QUANTITY),
       SUM(SPC.QUANTITY)
FROM SHIPMENT S
INNER JOIN SHIPMENT_ITEM SI ON SI.SHIPMENT_ID = S.SHIPMENT_ID
INNER JOIN SHIPMENT_ROUTE_SEGMENT SRS ON SRS.SHIPMENT_ID = S.SHIPMENT_ID
INNER JOIN SHIPMENT_PACKAGE_CONTENT SPC ON SPC.SHIPMENT_ID = SI.SHIPMENT_ID AND SPC.PRODUCT_ID = SI.PRODUCT_ID
WHERE S.SHIPMENT_TYPE_ENUM_ID IN ('SHPTPSALES','SHPTPOUTGOING')
    AND SRS.ACTUAL_START_DATE BETWEEN '2023-01-20 00:00' AND '2023-01-21 00:00'
    AND S.STATUS_ID IN ('SHIPSHIPPED','SHIPDELIVERED')
GROUP BY SRS.ORIGIN_FACILITY_ID, S.PRODUCT_STORE_ID
ORDER BY S.PRODUCT_STORE_ID DESC;

SELECT *
FROM PRODUCT OP
         INNER JOIN PRODUCT_IDENTIFICATION PIO ON PIO.PRODUCT_ID = OP.PRODUCT_ID
    AND PIO.PRODUCT_ID_TYPE_ENUM_ID = 'PidtUpca'
         INNER JOIN (SELECT PI.ID_VALUE,
                            COUNT(*)
                     FROM PRODUCT_IDENTIFICATION PI
                              INNER JOIN PRODUCT P ON PI.PRODUCT_ID = P.PRODUCT_ID
                         AND PI.PRODUCT_ID_TYPE_ENUM_ID = 'PidtUpca'
                     WHERE P.OWNER_PARTY_ID NOT IN (
                                                    'HONEYWELL',
                                                    'HONEYWELLEMEA',
                                                    'MUCKCA',
                                                    'AMICW',
                                                    'SRIO'
                         )
                       AND P.PRODUCT_TYPE_ENUM_ID = 'PtAsset'
                     GROUP BY PI.ID_VALUE
                     HAVING COUNT(*) > 1) AS DUPS ON DUPS.ID_VALUE = PIO.ID_VALUE
WHERE OP.OWNER_PARTY_ID = 'CHRM';


SELECT AR.ORDER_ID,
       AR.PRODUCT_ID,
       AR.ASSET_RESERVATION_ID,
       AR.QUANTITY,
       A.LOCATION_SEQ_ID,
       A.STATUS_ID,
       A.FACILITY_ID
FROM ASSET_RESERVATION AR
INNER JOIN ORDER_ITEM OI ON OI.ORDER_ID = AR.ORDER_ID AND OI.ORDER_ITEM_SEQ_ID = AR.ORDER_ITEM_SEQ_ID
INNER JOIN ORDER_PART OP ON OP.ORDER_ID = OI.ORDER_ID AND OP.ORDER_PART_SEQ_ID = OI.ORDER_PART_SEQ_ID
INNER JOIN ORDER_HEADER OH ON OH.ORDER_ID = OI.ORDER_ID
INNER JOIN ASSET A ON A.ASSET_ID = AR.ASSET_ID
WHERE OH.PRODUCT_STORE_ID = 'KCNY_SHOPIFY'
AND OH.STATUS_ID = 'ORDERAPPROVED'
AND OP.CUSTOMER_PARTY_ID <> 'KCNY'
LIMIT 100;

SELECT *
FROM PHYSICAL_INVENTORY PI
WHERE PI.PHYSICAL_INVENTORY_ID IN ('11535808');

SELECT PI.PHYSICAL_INVENTORY_ID,
       PI.PHYSICAL_INVENTORY_DATE,
       AD.ASSET_ID,
       AD.QUANTITY_ON_HAND_DIFF,
       A.PRODUCT_ID,
       A.LOCATION_SEQ_ID,
       A.FACILITY_ID
FROM PHYSICAL_INVENTORY PI
INNER JOIN ASSET_DETAIL AD ON AD.PHYSICAL_INVENTORY_ID = PI.PHYSICAL_INVENTORY_ID
INNER JOIN ASSET A ON A.ASSET_ID = AD.ASSET_ID
WHERE PI.PHYSICAL_INVENTORY_DATE BETWEEN '2023-08-25 00:00:00' AND '2023-08-26 00:00:00'
AND A.OWNER_PARTY_ID = 'BOL'
AND A.FACILITY_ID = 'NOG_DC_PITTSBURGH_FACILITY';

-- mantle.product.AssetServices.record#PhysicalInventoryChange
-- undo the changes done by an 846
SELECT A.STATUS_ID as 'statusId',
       A.OWNER_PARTY_ID as 'ownerPartyId',
       A.PRODUCT_ID as 'productId',
       A.FACILITY_ID as 'facilityId',
       A.LOCATION_SEQ_ID as 'locationSeqId',
       -(AD.QUANTITY_ON_HAND_DIFF) as 'quantityChange'
FROM PHYSICAL_INVENTORY PI
INNER JOIN ASSET_DETAIL AD ON AD.PHYSICAL_INVENTORY_ID = PI.PHYSICAL_INVENTORY_ID
INNER JOIN ASSET A ON A.ASSET_ID = AD.ASSET_ID
WHERE PI.PHYSICAL_INVENTORY_DATE BETWEEN '2023-08-25 00:00:00' AND '2023-08-25 00:00:00'
AND PI.PARTY_ID IS NULL
AND A.OWNER_PARTY_ID = 'KCNY'
AND A.FACILITY_ID = 'NOG_DC_PITTSBURGH_FACILITY';

-- mantle.product.AssetServices.change#AssetQuantity
-- adjust inventory back in from rogue import
SELECT A.ASSET_ID as 'assetId',
       AD.QUANTITY_ON_HAND_DIFF as 'quantityDiff',
       '11543750' as 'physicalInventoryId',
       A.LOCATION_SEQ_ID,
       P.PSEUDO_ID,
       P.PRODUCT_NAME
FROM PHYSICAL_INVENTORY PINV
INNER JOIN ASSET_DETAIL AD ON AD.PHYSICAL_INVENTORY_ID = PINV.PHYSICAL_INVENTORY_ID AND AD.QUANTITY_ON_HAND_DIFF > 0
INNER JOIN ASSET A ON A.ASSET_ID = AD.ASSET_ID AND A.QUANTITY_ON_HAND_TOTAL > 0
INNER JOIN PHYSICAL_INVENTORY PI ON PINV.PHYSICAL_INVENTORY_ID = AD.PHYSICAL_INVENTORY_ID AND PINV.PARTY_ID IS NULL
INNER JOIN PRODUCT P ON P.PRODUCT_ID = A.PRODUCT_ID
WHERE PINV.PHYSICAL_INVENTORY_DATE BETWEEN '2023-08-25 13:00:00' AND '2023-08-25 14:00:00'
AND A.OWNER_PARTY_ID = 'KCNY'
AND A.FACILITY_ID = 'NOG_DC_PITTSBURGH_FACILITY'
#AND AD.VARIANCE_REASON_ENUM_ID = 'InVrFound'
AND PINV.PHYSICAL_INVENTORY_ID NOT IN ('11543750')
AND P.OWNER_PARTY_ID = 'KCNY'
GROUP BY A.ASSET_ID, PINV.PHYSICAL_INVENTORY_ID;


SELECT A.ASSET_ID as 'assetId',
       A.QUANTITY_ON_HAND_TOTAL as 'quantityDiff',
       P.PSEUDO_ID,
       P.PRODUCT_NAME,
       A.QUANTITY_ON_HAND_TOTAL,
       A.OWNER_PARTY_ID,
       A.FACILITY_ID,
       A.LOCATION_SEQ_ID,
       PERS.FIRST_NAME,
       PERS.LAST_NAME
FROM ASSET A
INNER JOIN PRODUCT P ON P.PRODUCT_ID = A.PRODUCT_ID
INNER JOIN ASSET_DETAIL AD ON AD.ASSET_ID = A.ASSET_ID
    AND AD.QUANTITY_ON_HAND_DIFF > 0
INNER JOIN PHYSICAL_INVENTORY PI ON PI.PHYSICAL_INVENTORY_ID = AD.PHYSICAL_INVENTORY_ID
    AND PI.PARTY_ID IS NOT NULL
    AND PI.PHYSICAL_INVENTORY_ID NOT IN ('10523716','10513107')
INNER JOIN PERSON PERS ON PERS.PARTY_ID = PI.PARTY_ID
WHERE A.OWNER_PARTY_ID = 'BOL'
AND A.FACILITY_ID = 'NOG_DC_PITTSBURGH_FACILITY'
AND A.QUANTITY_ON_HAND_TOTAL > 0;


-- see when the biggest changes happened
SELECT SUM(CASE WHEN PI.PHYSICAL_INVENTORY_DATE BETWEEN '2023-02-03 00:00:00' AND '2023-02-03 01:00:00'
    THEN AD.QUANTITY_ON_HAND_DIFF
    ELSE 0 END) AS '12AM',
    SUM(CASE WHEN PI.PHYSICAL_INVENTORY_DATE BETWEEN '2023-02-03 01:00:00' AND '2023-02-03 02:00:00'
    THEN AD.QUANTITY_ON_HAND_DIFF
    ELSE 0 END) AS '1AM',
    SUM(CASE WHEN PI.PHYSICAL_INVENTORY_DATE BETWEEN '2023-02-03 02:00:00' AND '2023-02-03 03:00:00'
    THEN AD.QUANTITY_ON_HAND_DIFF
    ELSE 0 END) AS '2AM',
    SUM(CASE WHEN PI.PHYSICAL_INVENTORY_DATE BETWEEN '2023-02-03 03:00:00' AND '2023-02-03 04:00:00'
    THEN AD.QUANTITY_ON_HAND_DIFF
    ELSE 0 END) AS '3AM',
    SUM(CASE WHEN PI.PHYSICAL_INVENTORY_DATE BETWEEN '2023-02-03 04:00:00' AND '2023-02-03 05:00:00'
    THEN AD.QUANTITY_ON_HAND_DIFF
    ELSE 0 END) AS '4AM',
    SUM(CASE WHEN PI.PHYSICAL_INVENTORY_DATE BETWEEN '2023-02-03 05:00:00' AND '2023-02-03 06:00:00'
    THEN AD.QUANTITY_ON_HAND_DIFF
    ELSE 0 END) AS '5AM',
    SUM(CASE WHEN PI.PHYSICAL_INVENTORY_DATE BETWEEN '2023-02-03 06:00:00' AND '2023-02-03 07:00:00'
    THEN AD.QUANTITY_ON_HAND_DIFF
    ELSE 0 END) AS '6AM',
    SUM(CASE WHEN PI.PHYSICAL_INVENTORY_DATE BETWEEN '2023-02-03 07:00:00' AND '2023-02-03 08:00:00'
    THEN AD.QUANTITY_ON_HAND_DIFF
    ELSE 0 END) AS '7AM',
    SUM(CASE WHEN PI.PHYSICAL_INVENTORY_DATE BETWEEN '2023-02-03 08:00:00' AND '2023-02-03 09:00:00'
    THEN AD.QUANTITY_ON_HAND_DIFF
    ELSE 0 END) AS '8AM',
    SUM(CASE WHEN PI.PHYSICAL_INVENTORY_DATE BETWEEN '2023-02-03 00:00:00' AND '2023-02-04 00:00:00'
    THEN AD.QUANTITY_ON_HAND_DIFF
    ELSE 0 END) AS 'Feb3 Ttl',
    SUM(CASE WHEN PI.PHYSICAL_INVENTORY_DATE BETWEEN '2023-02-04 00:00:00' AND '2023-02-05 00:00:00'
    THEN AD.QUANTITY_ON_HAND_DIFF
    ELSE 0 END) AS 'Feb4 Ttl',
    SUM(CASE WHEN PI.PHYSICAL_INVENTORY_DATE BETWEEN '2023-02-05 00:00:00' AND '2023-02-06 00:00:00'
    THEN AD.QUANTITY_ON_HAND_DIFF
    ELSE 0 END) AS 'Feb5 Ttl',
    SUM(CASE WHEN PI.PHYSICAL_INVENTORY_DATE BETWEEN '2023-02-06 00:00:00' AND '2023-02-07 00:00:00'
    THEN AD.QUANTITY_ON_HAND_DIFF
    ELSE 0 END) AS 'Feb6 Ttl'
FROM PHYSICAL_INVENTORY PI
INNER JOIN ASSET_DETAIL AD ON AD.PHYSICAL_INVENTORY_ID = PI.PHYSICAL_INVENTORY_ID
INNER JOIN ASSET A ON A.ASSET_ID = AD.ASSET_ID
WHERE A.OWNER_PARTY_ID = 'BOL'
AND A.FACILITY_ID = 'NOG_DC_PITTSBURGH_FACILITY';


SELECT *
FROM ASSET_SNAPSHOT_HISTORY ASH
INNER JOIN PRODUCT P ON P.PRODUCT_ID = ASH.PRODUCT_ID
WHERE ASH.FACILITY_ID = 'NOG_DC_PITTSBURGH_FACILITY'
AND P.OWNER_PARTY_ID = 'KCNY'
ORDER BY AS_ON_DATETIME DESC
LIMIT 100;

SELECT OH.PRODUCT_STORE_ID,
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2022-01-01 00:00:00' AND '2022-02-01 00:00:00'
           THEN 1
           ELSE 0 END) AS 'JAN22',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2022-02-01 00:00:00' AND '2022-03-01 00:00:00'
           THEN 1
           ELSE 0 END) AS 'FEB22',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2022-03-01 00:00:00' AND '2022-04-01 00:00:00'
           THEN 1
           ELSE 0 END) AS 'MAR22',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2022-04-01 00:00:00' AND '2022-05-01 00:00:00'
           THEN 1
           ELSE 0 END) AS 'APR22',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2022-05-01 00:00:00' AND '2022-06-01 00:00:00'
           THEN 1
           ELSE 0 END) AS 'MAY22',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2022-06-01 00:00:00' AND '2022-07-01 00:00:00'
           THEN 1
           ELSE 0 END) AS 'JUN22',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2022-07-01 00:00:00' AND '2022-08-01 00:00:00'
           THEN 1
           ELSE 0 END) AS 'JUL22',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2022-08-01 00:00:00' AND '2022-09-01 00:00:00'
           THEN 1
           ELSE 0 END) AS 'AUG22',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2022-09-01 00:00:00' AND '2022-10-01 00:00:00'
           THEN 1
           ELSE 0 END) AS 'SEP22',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2022-10-01 00:00:00' AND '2022-11-01 00:00:00'
           THEN 1
           ELSE 0 END) AS 'OCT22',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2022-11-01 00:00:00' AND '2022-12-01 00:00:00'
           THEN 1
           ELSE 0 END) AS 'NOV22',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2022-12-01 00:00:00' AND '2023-01-01 00:00:00'
           THEN 1
           ELSE 0 END) AS 'DEC22',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-01-01 00:00:00' AND '2023-02-01 00:00:00'
           THEN 1
           ELSE 0 END) AS 'JAN23',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-02-01 00:00:00' AND '2023-03-01 00:00:00'
           THEN 1
           ELSE 0 END) AS 'FEB23',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-03-01 00:00:00' AND '2023-04-01 00:00:00'
           THEN 1
           ELSE 0 END) AS 'MAR23'
FROM ORDER_HEADER OH
WHERE OH.PRODUCT_STORE_ID LIKE ('%_SHOPIFY')
AND OH.SALES_CHANNEL_ENUM_ID = 'SCSHOPIFY'
GROUP BY OH.PRODUCT_STORE_ID;

SELECT OP.FACILITY_ID,
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2022-01-01 00:00:00' AND '2023-01-01 00:00:00'
        THEN 1
        ELSE 0 END) AS '2022 SUM',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2022-10-01 00:00:00' AND '2022-11-01 00:00:00'
           THEN 1
           ELSE 0 END) AS 'OCT22',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2022-11-01 00:00:00' AND '2022-12-01 00:00:00'
           THEN 1
           ELSE 0 END) AS 'NOV22',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2022-12-01 00:00:00' AND '2023-01-01 00:00:00'
           THEN 1
           ELSE 0 END) AS 'DEC22',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-01-01 00:00:00' AND '2023-02-01 00:00:00'
           THEN 1
           ELSE 0 END) AS 'JAN23',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-02-01 00:00:00' AND '2023-03-01 00:00:00'
           THEN 1
           ELSE 0 END) AS 'FEB23',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-03-01 00:00:00' AND '2023-04-01 00:00:00'
           THEN 1
           ELSE 0 END) AS 'MAR23',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-04-01 00:00:00' AND '2023-05-01 00:00:00'
           THEN 1
           ELSE 0 END) AS 'APR23'
FROM ORDER_PART OP
INNER JOIN ORDER_HEADER OH ON OH.ORDER_ID = OP.ORDER_ID
WHERE OP.VENDOR_PARTY_ID = 'BROOK'
GROUP BY OP.FACILITY_ID;


# assetReceipt report duplicate when editing old receipts
SELECT
    A.OWNER_PARTY_ID,
    P.PSEUDO_ID,
    P.PRODUCT_NAME,
    AR.SHIPMENT_ID,
    S.OTHER_PARTY_ORDER_ID,
    AR.RETURN_ID,
    AR.RECEIVED_DATE,
    UA.USER_FULL_NAME,
    AR.RECEIVED_BY_USER_ID,
    SI.QUANTITY,
    SUM(AR.QUANTITY_ACCEPTED),
    SUM(AR.QUANTITY_REJECTED),
    AR.REJECTION_REASON_ENUM_ID,
    P.OWNER_PARTY_ID,
    A.FACILITY_ID,
    A.ASSET_POOL_ID,
    SI.ORIGINAL_QUANTITY,
    A.ASSET_ID,
    S.STATUS_ID
FROM ASSET_RECEIPT AR
INNER JOIN ASSET A ON A.ASSET_ID = AR.ASSET_ID
INNER JOIN PRODUCT P ON P.PRODUCT_ID = AR.PRODUCT_ID
INNER JOIN SHIPMENT S ON S.SHIPMENT_ID = AR.SHIPMENT_ID
INNER JOIN USER_ACCOUNT UA ON UA.USER_ID = AR.RECEIVED_BY_USER_ID
INNER JOIN SHIPMENT_ITEM SI ON SI.SHIPMENT_ID = AR.SHIPMENT_ID AND SI.PRODUCT_ID = AR.PRODUCT_ID
WHERE S.SHIPMENT_ID = '5007473'
GROUP BY A.OWNER_PARTY_ID, P.PSEUDO_ID, P.PRODUCT_NAME, AR.SHIPMENT_ID, S.OTHER_PARTY_ORDER_ID, AR.RETURN_ID, AR.RECEIVED_DATE, UA.USER_FULL_NAME, AR.RECEIVED_BY_USER_ID, SI.QUANTITY, AR.REJECTION_REASON_ENUM_ID, P.OWNER_PARTY_ID, A.FACILITY_ID, A.ASSET_POOL_ID, SI.ORIGINAL_QUANTITY, A.ASSET_ID, S.STATUS_ID;

SELECT SIS.SHIPMENT_ID,
       SPC.SHIPMENT_ID,
       SIS.ORDER_ID,
       SIS.PRODUCT_ID,
       SIS.QUANTITY,
       OI.QUANTITY as 'OI QTY',
    SUM(SPC.QUANTITY)
FROM SHIPMENT_PACKAGE_CONTENT SPC
INNER JOIN PRODUCT P ON P.PRODUCT_ID = SPC.PRODUCT_ID
LEFT JOIN SHIPMENT_ITEM_SOURCE SIS ON SIS.SHIPMENT_ID = SPC.SHIPMENT_ID AND SIS.PRODUCT_ID = SPC.PRODUCT_ID
LEFT JOIN ORDER_ITEM OI ON OI.ORDER_ID = SIS.ORDER_ID AND OI.ORDER_ITEM_SEQ_ID = SIS.ORDER_ITEM_SEQ_ID
WHERE P.PSEUDO_ID = 'DTX00001KIT'
AND SPC.LAST_UPDATED_STAMP BETWEEN '2023-03-01 00:00' AND '2023-04-01 00:00'
GROUP BY SIS.SHIPMENT_ID, SPC.SHIPMENT_ID, SIS.ORDER_ID, SIS.PRODUCT_ID;

/*
 scan/pack only available reserved units
 mantle.shipment.ShipmentServices.pack#ShipmentProductScan
 */
SELECT SIS.SHIPMENT_ID as 'shipmentId',
       AR.PRODUCT_ID as 'productId',
       '' AS 'shipmentPackageSeqId',
       AR.QUANTITY_NOT_ISSUED as 'quantity',
       AR.QUANTITY_NOT_AVAILABLE,
       S.STATUS_ID,
       SIS.ORDER_ID,
       AR.ASSET_ID as 'assetId'
FROM ASSET_RESERVATION AR
INNER JOIN SHIPMENT_ITEM_SOURCE SIS ON SIS.ORDER_ID = AR.ORDER_ID AND SIS.ORDER_ITEM_SEQ_ID = AR.ORDER_ITEM_SEQ_ID
INNER JOIN SHIPMENT S ON S.SHIPMENT_ID = SIS.SHIPMENT_ID
INNER JOIN PRODUCT_IDENTIFICATION PI ON PI.PRODUCT_ID = AR.PRODUCT_ID AND PI.PRODUCT_ID_TYPE_ENUM_ID = 'PIDTUPCA'
WHERE AR.ORDER_ID IN ('5862964')
AND S.STATUS_ID NOT IN ('SHIPSHIPPED','SHIPCANCELLED')
AND AR.QUANTITY_NOT_AVAILABLE = 0;

SELECT SIS.ORDER_ID,
       SIS.PRODUCT_ID,
       SIS.QUANTITY,
       SIS.QUANTITY_PICKED,
       SIS.QUANTITY_NOT_HANDLED,
       AR.ASSET_ID
FROM SHIPMENT_ITEM_SOURCE SIS
INNER JOIN ASSET_RESERVATION AR ON AR.ORDER_ID = SIS.ORDER_ID AND AR.ORDER_ITEM_SEQ_ID = SIS.ORDER_ITEM_SEQ_ID
INNER JOIN ASSET A ON A.ASSET_ID = AR.ASSET_ID AND A.QUANTITY_ON_HAND_TOTAL > 0
WHERE SIS.ORDER_ID = '5864930'
GROUP BY SIS.ORDER_ID, SIS.PRODUCT_ID, SIS.QUANTITY, SIS.QUANTITY_PICKED, SIS.QUANTITY_NOT_HANDLED, AR.ASSET_ID;

/*
 Fixing KK Selling Report's product feature applications
 delete#mantle.product.feature.ProductFeatureAppl
 */
SELECT PFA.PRODUCT_ID as 'productId',
       PFA.PRODUCT_FEATURE_ID as 'productFeatureId',
       PFA.FROM_DATE as 'fromDate',
       PFA.THRU_DATE,
       PF.DESCRIPTION,
       PF.PRODUCT_FEATURE_TYPE_ENUM_ID
FROM PRODUCT_FEATURE_APPL PFA
INNER JOIN PRODUCT_FEATURE PF ON PF.PRODUCT_FEATURE_ID = PFA.PRODUCT_FEATURE_ID
INNER JOIN PRODUCT P ON P.PRODUCT_ID = PFA.PRODUCT_ID
WHERE PF.PRODUCT_FEATURE_TYPE_ENUM_ID = 'PFTSIZECHART'
AND PF.DESCRIPTION = 'APPAREL'
AND P.OWNER_PARTY_ID = 'KK';

SELECT PFA.PRODUCT_ID,
       MAX(PFA.FROM_DATE)
FROM PRODUCT_FEATURE_APPL PFA
INNER JOIN PRODUCT_FEATURE PF ON PF.PRODUCT_FEATURE_ID = PFA.PRODUCT_FEATURE_ID
INNER JOIN PRODUCT P ON P.PRODUCT_ID = PFA.PRODUCT_ID
WHERE PF.PRODUCT_FEATURE_TYPE_ENUM_ID = 'PFTGROUP'
AND P.OWNER_PARTY_ID = 'KK'
AND PFA.PRODUCT_ID = '1698830'
GROUP BY PFA.PRODUCT_ID;

/*
 get the latest group tag
 */
SELECT PFA.PRODUCT_ID as 'productId',
       PFA.PRODUCT_FEATURE_ID as 'productFeatureId',
       PFA.FROM_DATE as 'fromDate',
       PFA.THRU_DATE,
       PF.DESCRIPTION,
       PF.PRODUCT_FEATURE_TYPE_ENUM_ID
FROM PRODUCT_FEATURE_APPL PFA
INNER JOIN PRODUCT_FEATURE PF ON PF.PRODUCT_FEATURE_ID = PFA.PRODUCT_FEATURE_ID
INNER JOIN PRODUCT P ON P.PRODUCT_ID = PFA.PRODUCT_ID
INNER JOIN
     (SELECT PFA2.PRODUCT_ID,
             MAX(PFA2.FROM_DATE) AS 'FROM_DATE'
      FROM PRODUCT_FEATURE_APPL PFA2
               INNER JOIN PRODUCT_FEATURE PF2 ON PF2.PRODUCT_FEATURE_ID = PFA2.PRODUCT_FEATURE_ID
               INNER JOIN PRODUCT P ON P.PRODUCT_ID = PFA2.PRODUCT_ID
      WHERE PF2.PRODUCT_FEATURE_TYPE_ENUM_ID = 'PFTGROUP'
        AND P.OWNER_PARTY_ID = 'KK'
      GROUP BY PFA2.PRODUCT_ID) MAX_FROMDATE ON MAX_FROMDATE.PRODUCT_ID = PFA.PRODUCT_ID AND MAX_FROMDATE.FROM_DATE = PFA.FROM_DATE
WHERE PF.PRODUCT_FEATURE_TYPE_ENUM_ID = 'PFTGROUP'
AND PFA.THRU_DATE IS NOT NULL
AND P.OWNER_PARTY_ID = 'KK';


SELECT IA.PRODUCT_ID,
       P.PSEUDO_ID,
       IA.INVENTORY,
       IA.SHOPIFY_INVENTORY,
       IA.INVENTORY - IA.SHOPIFY_INVENTORY AS 'diff'
FROM INVENTORY_AUDIT IA
INNER JOIN PRODUCT P ON P.PRODUCT_ID = IA.PRODUCT_ID
WHERE IA.INTEGRATION_ID = 'BETA_SHOPIFY'
AND IA.LAST_UPDATED_STAMP > '2023-05-04 00:00'
AND (IA.INVENTORY - IA.SHOPIFY_INVENTORY) <> 0;

/*
 looking for cancelled orders to verify the return & refund details reports
 */
SELECT *
FROM ORDER_ITEM OI
INNER JOIN ORDER_PART OP ON OP.ORDER_ID = OI.ORDER_ID AND OP.ORDER_PART_SEQ_ID = OI.ORDER_PART_SEQ_ID
INNER JOIN ORDER_HEADER OH ON OH.ORDER_ID = OI.ORDER_ID
WHERE OP.VENDOR_PARTY_ID = 'ALY'
AND OI.QUANTITY_CANCELLED > 0
AND OH.PLACED_DATE > '2023-04-01 00:00:00'
AND OI.ITEM_TYPE_ENUM_ID = 'ItemProduct'
ORDER BY OH.PLACED_DATE ASC
LIMIT 30;



/*
 trying to find where users direct received assets
 ricky's query below
 */
SELECT P.PSEUDO_ID,
       A.ASSET_ID, -- these items were received with no shipment
       A.QUANTITY_ON_HAND_TOTAL,
       A.LOCATION_SEQ_ID,
       AD.AVAILABLE_TO_PROMISE_DIFF,
       AD.QUANTITY_ON_HAND_DIFF,
       A2.ASSET_ID,
       A2.QUANTITY_ON_HAND_TOTAL,
       A2.LOCATION_SEQ_ID
FROM ASSET A
INNER JOIN ASSET_DETAIL AD ON AD.ASSET_ID = A.ASSET_ID
                                  AND AD.ASSET_RECEIPT_ID IS NOT NULL
                                  AND AD.SHIPMENT_ID IS NULL -- get receipts with no shipments
INNER JOIN PRODUCT P ON P.PRODUCT_ID = A.PRODUCT_ID
INNER JOIN ASSET A2 ON A2.PRODUCT_ID = P.PRODUCT_ID
                           AND A2.LOCATION_SEQ_ID LIKE 'IMHD-RCV%'
                           AND A2.QUANTITY_ON_HAND_TOTAL > 0 -- items in receive location
WHERE A.OWNER_PARTY_ID = 'IMHD'
AND A.QUANTITY_ON_HAND_TOTAL > 0
AND A.LOCATION_SEQ_ID NOT LIKE 'IMHD-RCV%';

select A.OWNER_PARTY_ID,
       A.PRODUCT_ID,
       A.ASSET_NAME,
       A.ASSET_ID,
       A.QUANTITY_ON_HAND_TOTAL,
       A.ORIGINAL_QUANTITY,
       A.LOCATION_SEQ_ID,
       A.RECEIVED_DATE,
       A2.ASSET_ID               as 'Asset id to compare',
       A2.QUANTITY_ON_HAND_TOTAL as 'ATP total to compare',
       A2.ORIGINAL_QUANTITY      as 'Original Qty to compare',
       A2.LOCATION_SEQ_ID        as 'Location to compare',
       A2.RECEIVED_DATE          as 'Received date to compare'
from ASSET A
         inner join ASSET A2
where A2.PRODUCT_ID = A.PRODUCT_ID
  and A2.RECEIVED_DATE = A.RECEIVED_DATE
  and A.LOCATION_SEQ_ID LIKE 'IMHD-RCV%'
  and A.FACILITY_ID = 'NOG_DC_PITTSBURGH_FACILITY'
  and A.OWNER_PARTY_ID = 'IMHD'
  and A.AVAILABLE_TO_PROMISE_TOTAL > 0
  and A2.FACILITY_ID = 'NOG_DC_PITTSBURGH_FACILITY'
  and A2.OWNER_PARTY_ID = 'IMHD'
  and A2.LOCATION_SEQ_ID NOT LIKE 'IMHD-RCV%'
order by A.PRODUCT_ID;

/*
 andy request 2023-06-07
 IMHD cancelled quantity from orders
 */
SELECT OH.ORDER_ID,
       OH.DISPLAY_ID,
       OH.STATUS_ID as 'Order Header Status',
       OP.ORDER_PART_SEQ_ID,
       OP.FACILITY_ID,
       OP.STATUS_ID as 'Order Part Status',
       OH.ENTRY_DATE,
       OI.OTHER_PARTY_PRODUCT_ID,
       OI.ORIGINAL_QUANTITY,
       OI.QUANTITY,
       OI.QUANTITY_CANCELLED
