INNER JOIN ORDER_PART OP ON OP.ORDER_ID = OH.ORDER_ID
INNER JOIN ORDER_ITEM OI ON OI.ORDER_ID = OP.ORDER_ID AND OI.ORDER_PART_SEQ_ID = OP.ORDER_PART_SEQ_ID
WHERE OH.PRODUCT_STORE_ID = 'IMHD_SHOPIFY'
AND OI.ITEM_TYPE_ENUM_ID = 'ItemProduct';

SELECT *
FROM ASSET_RESERVATION AR
INNER JOIN ORDER_HEADER OH ON OH.ORDER_ID = AR.ORDER_ID
INNER JOIN ORDER_ITEM OI ON OI.ORDER_ID = AR.ORDER_ID AND OI.ORDER_ITEM_SEQ_ID = AR.ORDER_ITEM_SEQ_ID
INNER JOIN ORDER_PART OP ON OP.ORDER_ID = OI.ORDER_ID AND OP.ORDER_PART_SEQ_ID = OI.ORDER_PART_SEQ_ID
WHERE OH.PRODUCT_STORE_ID = 'JUST_SHOPIFY'
AND OH.STATUS_ID = 'ORDERCOMPLETED'
AND OP.FACILITY_ID = 'BOL_DC_FONTANA_2'
AND OP.STATUS_ID = 'ORDERCOMPLETED';

SELECT P.PSEUDO_ID as 'parent style',
       P.SALES_DISCONTINUATION_DATE,
       P.STATUS_ID,
       PA.PRODUCT_ID as 'productId',
       PA.TO_PRODUCT_ID as 'toProductId',
       PA.PRODUCT_ASSOC_TYPE_ENUM_ID as 'productAssocTypeEnumId',
       PA.FROM_DATE as 'fromDate',
       P2.PSEUDO_ID as 'to sku',
       IP.EXTERNAL_ID as 'ext parent id'
FROM PRODUCT_ASSOC PA
INNER JOIN PRODUCT P ON P.PRODUCT_ID = PA.PRODUCT_ID
