WHERE P.OWNER_PARTY_ID = 'KK'
#AND P.PSEUDO_ID LIKE ('L13530%');

SELECT IP.EXTERNAL_ID,
       IP.EXTERNAL_PARENT_ID,
       IP.EXTERNAL_SECONDARY_ID,
       IP.INTEGRATION_PRODUCT_STATUS_ID,
       IP.PRODUCT_ID,
       IP.PRIMARY_MAP_VALUE,
       IP.INTEGRATION_PRODUCT_ID
FROM INTEGRATION_PRODUCT IP
WHERE IP.INTEGRATION_ID = 'KK_SHOPIFY';

/*
 look for assets reserved against bulk for Justice
 */
SELECT AR.ORDER_ID,
    A.PRODUCT_ID,
       A.LOCATION_SEQ_ID,
       FL.LOCATION_TYPE_ENUM_ID,
       A.FACILITY_ID,
       APKLOC.sumAtp,
       APKLOC.sumQoh,
       APKLOC.LOCATION_SEQ_ID
FROM ASSET A
INNER JOIN ASSET_RESERVATION AR ON AR.ASSET_ID = A.ASSET_ID
INNER JOIN ORDER_ITEM OI ON OI.ORDER_ID = AR.ORDER_ID AND OI.ORDER_ITEM_SEQ_ID = AR.ORDER_ITEM_SEQ_ID
INNER JOIN ORDER_PART OP ON OP.ORDER_ID = OI.ORDER_ID AND OP.ORDER_PART_SEQ_ID = OI.ORDER_PART_SEQ_ID
INNER JOIN ORDER_HEADER OH ON OH.ORDER_ID = OP.ORDER_ID
INNER JOIN FACILITY_LOCATION FL ON FL.LOCATION_SEQ_ID = A.LOCATION_SEQ_ID
LEFT JOIN (
    SELECT A2.PRODUCT_ID,
           SUM(A2.QUANTITY_ON_HAND_TOTAL) as 'sumQoh',
           SUM(A2.AVAILABLE_TO_PROMISE_TOTAL) as 'sumAtp',
           A2.LOCATION_SEQ_ID
    FROM ASSET A2
    INNER JOIN FACILITY_LOCATION FL2 ON FL2.LOCATION_SEQ_ID = A2.LOCATION_SEQ_ID
    WHERE A2.OWNER_PARTY_ID = 'JUST'
    AND A2.FACILITY_ID = 'NOG_DC_PITTSBURGH_FACILITY'
    AND A2.STATUS_ID = 'ASTAVAILABLE'
    AND A2.QUANTITY_ON_HAND_TOTAL > 0
    AND FL2.LOCATION_TYPE_ENUM_ID = 'FLTPICK'
    GROUP BY A2.PRODUCT_ID, A2.LOCATION_SEQ_ID
) APKLOC ON APKLOC.PRODUCT_ID = OI.PRODUCT_ID
WHERE A.FACILITY_ID = 'NOG_DC_PITTSBURGH_FACILITY'
AND OH.PRODUCT_STORE_ID = 'JUST_SHOPIFY'
AND APKLOC.sumAtp > 0
AND FL.LOCATION_TYPE_ENUM_ID = 'FLTBULK'
LIMIT 100;

SELECT AS2.*,
       P.PSEUDO_ID
FROM ASSET_SNAPSHOT_HISTORY AS2
INNER JOIN PRODUCT P ON P.PRODUCT_ID = AS2.PRODUCT_ID
WHERE P.OWNER_PARTY_ID = 'JUST'
#AND AS2.FACILITY_ID = 'NOG_DC_PITTSBURGH_FACILITY'
ORDER BY AS2.AS_ON_DATETIME DESC
LIMIT 10;

