FROM ASSET_ON_HAND_SUMMARY_SNAPSHOT AOHSS
WHERE AOHSS.OWNER_PARTY_ID = 'JUST'
AND AOHSS.ENTITY_SNAPSHOT_ID > '158603';

SELECT *
