FROM ORDER_ITEM OI
WHERE OI.ORDER_ID IN ('6094981');

SELECT OH.ORDER_ID,
       OH.DISPLAY_ID,
       OH.ENTRY_DATE,
       OH.PLACED_DATE,
       OI.OTHER_PARTY_PRODUCT_ID,
       SUM(OI.QUANTITY)
