/*
 find the asset details of when this product was received
 */
SELECT P.PSEUDO_ID,
    A.ASSET_ID,
       A.FACILITY_ID,
       A.LOCATION_SEQ_ID,
       AD.EFFECTIVE_DATE,
       AD.QUANTITY_ON_HAND_DIFF,
       AD.AVAILABLE_TO_PROMISE_DIFF,
       AD.SHIPMENT_ID,
       AD.ASSET_RECEIPT_ID
FROM ASSET_DETAIL AD
INNER JOIN PRODUCT P ON P.PRODUCT_ID = AD.PRODUCT_ID
INNER JOIN ASSET A ON A.ASSET_ID = AD.ASSET_ID
WHERE P.PRODUCT_ID = '1806125'
AND EFFECTIVE_DATE  BETWEEN '2023-07-10 00:00:00' AND '2023-07-10 23:59:59'
AND A.FACILITY_ID = 'NOG_DC_PITTSBURGH_FACILITY';

SELECT P.PSEUDO_ID,
    A.ASSET_ID,
       A.FACILITY_ID,
       A.LOCATION_SEQ_ID,
       AD.*
FROM ASSET_DETAIL AD
INNER JOIN PRODUCT P ON P.PRODUCT_ID = AD.PRODUCT_ID
INNER JOIN ASSET A ON A.ASSET_ID = AD.ASSET_ID
WHERE P.PRODUCT_ID = '1806125'
AND EFFECTIVE_DATE  BETWEEN '2023-07-10 00:00:00' AND '2023-07-10 23:59:59'
AND A.FACILITY_ID = 'NOG_DC_PITTSBURGH_FACILITY';

/*
 drill down into the date -- looks like most ATP changes happened at 7/10
 */
SELECT P.PSEUDO_ID,
       A.FACILITY_ID,
       SUM(CASE WHEN AD.EFFECTIVE_DATE BETWEEN '2023-07-09 00:00:00' AND '2023-07-09 23:59:59'
           THEN AD.AVAILABLE_TO_PROMISE_DIFF
           ELSE 0 END) AS '07/09',
       SUM(CASE WHEN AD.EFFECTIVE_DATE BETWEEN '2023-07-10 00:00:00' AND '2023-07-10 23:59:59'
           THEN AD.AVAILABLE_TO_PROMISE_DIFF
           ELSE 0 END) AS '07/10',
    SUM(CASE WHEN AD.EFFECTIVE_DATE BETWEEN '2023-07-11 00:00:00' AND '2023-07-11 23:59:59'
           THEN AD.AVAILABLE_TO_PROMISE_DIFF
           ELSE 0 END) AS '07/11',
    SUM(CASE WHEN AD.EFFECTIVE_DATE BETWEEN '2023-07-12 00:00:00' AND '2023-07-12 23:59:59'
           THEN AD.AVAILABLE_TO_PROMISE_DIFF
           ELSE 0 END) AS '07/12'
FROM ASSET_DETAIL AD
INNER JOIN PRODUCT P ON P.PRODUCT_ID = AD.PRODUCT_ID
INNER JOIN ASSET A ON A.ASSET_ID = AD.ASSET_ID
WHERE P.PRODUCT_ID = '1806125'
AND EFFECTIVE_DATE BETWEEN '2023-07-10 00:00:00' AND '2023-07-10 23:59:59'
AND A.FACILITY_ID = 'NOG_DC_PITTSBURGH_FACILITY';

/*
 drill to hrs
 */
SELECT P.PSEUDO_ID,
       A.FACILITY_ID,
       SUM(CASE WHEN AD.EFFECTIVE_DATE BETWEEN '2023-07-10 00:00:00' AND '2023-07-10 00:59:59'
           THEN AD.AVAILABLE_TO_PROMISE_DIFF
           ELSE 0 END) AS '12 am',
    SUM(CASE WHEN AD.EFFECTIVE_DATE BETWEEN '2023-07-10 01:00:00' AND '2023-07-10 01:59:59'
           THEN AD.AVAILABLE_TO_PROMISE_DIFF
           ELSE 0 END) AS '1 am',
    SUM(CASE WHEN AD.EFFECTIVE_DATE BETWEEN '2023-07-10 02:00:00' AND '2023-07-11 02:59:59'
           THEN AD.AVAILABLE_TO_PROMISE_DIFF
           ELSE 0 END) AS '2am',
    SUM(CASE WHEN AD.EFFECTIVE_DATE BETWEEN '2023-07-10 03:00:00' AND '2023-07-10 03:59:59'
           THEN AD.AVAILABLE_TO_PROMISE_DIFF
           ELSE 0 END) AS '3 am',
    SUM(CASE WHEN AD.EFFECTIVE_DATE BETWEEN '2023-07-10 04:00:00' AND '2023-07-10 04:59:59'
           THEN AD.AVAILABLE_TO_PROMISE_DIFF
           ELSE 0 END) AS '4 am',
    SUM(CASE WHEN AD.EFFECTIVE_DATE BETWEEN '2023-07-10 05:00:00' AND '2023-07-10 05:59:59'
           THEN AD.AVAILABLE_TO_PROMISE_DIFF
           ELSE 0 END) AS '5 am',
    SUM(CASE WHEN AD.EFFECTIVE_DATE BETWEEN '2023-07-10 06:00:00' AND '2023-07-10 06:59:59'
           THEN AD.AVAILABLE_TO_PROMISE_DIFF
           ELSE 0 END) AS '6 am',
    SUM(CASE WHEN AD.EFFECTIVE_DATE BETWEEN '2023-07-10 07:00:00' AND '2023-07-10 07:59:59'
           THEN AD.AVAILABLE_TO_PROMISE_DIFF
           ELSE 0 END) AS '7 am',
    SUM(CASE WHEN AD.EFFECTIVE_DATE BETWEEN '2023-07-10 08:00:00' AND '2023-07-10 08:59:59'
           THEN AD.AVAILABLE_TO_PROMISE_DIFF
           ELSE 0 END) AS '8 am',
    SUM(CASE WHEN AD.EFFECTIVE_DATE BETWEEN '2023-07-10 09:00:00' AND '2023-07-10 09:59:59'
           THEN AD.AVAILABLE_TO_PROMISE_DIFF
           ELSE 0 END) AS '9 am',
    SUM(CASE WHEN AD.EFFECTIVE_DATE BETWEEN '2023-07-10 10:00:00' AND '2023-07-10 10:59:59'
           THEN AD.AVAILABLE_TO_PROMISE_DIFF
           ELSE 0 END) AS '10 am',
    SUM(CASE WHEN AD.EFFECTIVE_DATE BETWEEN '2023-07-10 11:00:00' AND '2023-07-10 11:59:59'
           THEN AD.AVAILABLE_TO_PROMISE_DIFF
           ELSE 0 END) AS '11 am',
    SUM(CASE WHEN AD.EFFECTIVE_DATE BETWEEN '2023-07-10 12:00:00' AND '2023-07-10 12:59:59'
           THEN AD.AVAILABLE_TO_PROMISE_DIFF
           ELSE 0 END) AS '12 pm',
    SUM(CASE WHEN AD.EFFECTIVE_DATE BETWEEN '2023-07-10 13:00:00' AND '2023-07-10 13:59:59'
           THEN AD.AVAILABLE_TO_PROMISE_DIFF
           ELSE 0 END) AS '1 pm',
    SUM(CASE WHEN AD.EFFECTIVE_DATE BETWEEN '2023-07-10 14:00:00' AND '2023-07-10 14:59:59'
           THEN AD.AVAILABLE_TO_PROMISE_DIFF
           ELSE 0 END) AS '2 pm',
    SUM(CASE WHEN AD.EFFECTIVE_DATE BETWEEN '2023-07-10 15:00:00' AND '2023-07-10 15:59:59'
           THEN AD.AVAILABLE_TO_PROMISE_DIFF
           ELSE 0 END) AS '3 pm',
    SUM(CASE WHEN AD.EFFECTIVE_DATE BETWEEN '2023-07-10 16:00:00' AND '2023-07-10 16:59:59'
           THEN AD.AVAILABLE_TO_PROMISE_DIFF
           ELSE 0 END) AS '4 pm',
    SUM(CASE WHEN AD.EFFECTIVE_DATE BETWEEN '2023-07-10 17:00:00' AND '2023-07-17 12:59:59'
           THEN AD.AVAILABLE_TO_PROMISE_DIFF
           ELSE 0 END) AS '5 pm',
    SUM(CASE WHEN AD.EFFECTIVE_DATE BETWEEN '2023-07-10 18:00:00' AND '2023-07-10 18:59:59'
           THEN AD.AVAILABLE_TO_PROMISE_DIFF
           ELSE 0 END) AS '6 pm',
    SUM(CASE WHEN AD.EFFECTIVE_DATE BETWEEN '2023-07-10 19:00:00' AND '2023-07-10 19:59:59'
           THEN AD.AVAILABLE_TO_PROMISE_DIFF
           ELSE 0 END) AS '7 pm',
    SUM(CASE WHEN AD.EFFECTIVE_DATE BETWEEN '2023-07-10 20:00:00' AND '2023-07-10 20:59:59'
           THEN AD.AVAILABLE_TO_PROMISE_DIFF
           ELSE 0 END) AS '8 pm',
    SUM(CASE WHEN AD.EFFECTIVE_DATE BETWEEN '2023-07-10 21:00:00' AND '2023-07-10 21:59:59'
           THEN AD.AVAILABLE_TO_PROMISE_DIFF
           ELSE 0 END) AS '9 pm',
    SUM(CASE WHEN AD.EFFECTIVE_DATE BETWEEN '2023-07-10 22:00:00' AND '2023-07-10 22:59:59'
           THEN AD.AVAILABLE_TO_PROMISE_DIFF
           ELSE 0 END) AS '10 pm',
    SUM(CASE WHEN AD.EFFECTIVE_DATE BETWEEN '2023-07-10 23:00:00' AND '2023-07-10 23:59:59'
           THEN AD.AVAILABLE_TO_PROMISE_DIFF
           ELSE 0 END) AS '11 pm'
FROM ASSET_DETAIL AD
INNER JOIN PRODUCT P ON P.PRODUCT_ID = AD.PRODUCT_ID
INNER JOIN ASSET A ON A.ASSET_ID = AD.ASSET_ID
WHERE P.PRODUCT_ID = '1806125'
AND EFFECTIVE_DATE BETWEEN '2023-07-10 00:00:00' AND '2023-07-10 23:59:59'
AND A.FACILITY_ID = 'NOG_DC_PITTSBURGH_FACILITY';


SELECT *
FROM ASSET_RESERVATION AR
WHERE AR.PRODUCT_ID = '1806125'
AND AR.RESERVED_DATE BETWEEN '2023-07-10 00:00:00' AND '2023-07-10 23:59:59';

/*
 look at the order queue for 7/10
 */
SELECT
       SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-07-10 00:00:00' AND '2023-07-10 00:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '12 am',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-07-10 01:00:00' AND '2023-07-10 01:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '1 am',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-07-10 02:00:00' AND '2023-07-11 02:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '2am',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-07-10 03:00:00' AND '2023-07-10 03:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '3 am',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-07-10 04:00:00' AND '2023-07-10 04:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '4 am',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-07-10 05:00:00' AND '2023-07-10 05:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '5 am',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-07-10 06:00:00' AND '2023-07-10 06:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '6 am',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-07-10 07:00:00' AND '2023-07-10 07:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '7 am',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-07-10 08:00:00' AND '2023-07-10 08:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '8 am',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-07-10 09:00:00' AND '2023-07-10 09:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '9 am',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-07-10 10:00:00' AND '2023-07-10 10:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '10 am',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-07-10 11:00:00' AND '2023-07-10 11:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '11 am',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-07-10 12:00:00' AND '2023-07-10 12:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '12 pm',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-07-10 13:00:00' AND '2023-07-10 13:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '1 pm',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-07-10 14:00:00' AND '2023-07-10 14:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '2 pm',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-07-10 15:00:00' AND '2023-07-10 15:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '3 pm',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-07-10 16:00:00' AND '2023-07-10 16:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '4 pm',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-07-10 17:00:00' AND '2023-07-17 12:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '5 pm',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-07-10 18:00:00' AND '2023-07-10 18:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '6 pm',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-07-10 19:00:00' AND '2023-07-10 19:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '7 pm',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-07-10 20:00:00' AND '2023-07-10 20:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '8 pm',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-07-10 21:00:00' AND '2023-07-10 21:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '9 pm',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-07-10 22:00:00' AND '2023-07-10 22:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '10 pm',
    SUM(CASE WHEN OH.PLACED_DATE BETWEEN '2023-07-10 23:00:00' AND '2023-07-10 23:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '11 pm'
FROM ORDER_HEADER OH
INNER JOIN ORDER_PART OP ON OP.ORDER_ID = OH.ORDER_ID
INNER JOIN ORDER_ITEM OI ON OI.ORDER_ID = OP.ORDER_ID AND OI.ORDER_PART_SEQ_ID = OP.ORDER_PART_SEQ_ID AND OI.ITEM_TYPE_ENUM_ID = 'ITEMPRODUCT'
WHERE OH.PLACED_DATE BETWEEN '2023-07-10 00:00:00' AND '2023-07-10 23:59:59'
AND OP.FACILITY_ID = 'NOG_DC_PITTSBURGH_FACILITY'
AND OI.PRODUCT_ID = '1806125';

/*
 look at entry date
 */
SELECT
       SUM(CASE WHEN OH.ENTRY_DATE BETWEEN '2023-07-10 00:00:00' AND '2023-07-10 00:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '12 am',
    SUM(CASE WHEN OH.ENTRY_DATE BETWEEN '2023-07-10 01:00:00' AND '2023-07-10 01:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '1 am',
    SUM(CASE WHEN OH.ENTRY_DATE BETWEEN '2023-07-10 02:00:00' AND '2023-07-11 02:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '2am',
    SUM(CASE WHEN OH.ENTRY_DATE BETWEEN '2023-07-10 03:00:00' AND '2023-07-10 03:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '3 am',
    SUM(CASE WHEN OH.ENTRY_DATE BETWEEN '2023-07-10 04:00:00' AND '2023-07-10 04:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '4 am',
    SUM(CASE WHEN OH.ENTRY_DATE BETWEEN '2023-07-10 05:00:00' AND '2023-07-10 05:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '5 am',
    SUM(CASE WHEN OH.ENTRY_DATE BETWEEN '2023-07-10 06:00:00' AND '2023-07-10 06:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '6 am',
    SUM(CASE WHEN OH.ENTRY_DATE BETWEEN '2023-07-10 07:00:00' AND '2023-07-10 07:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '7 am',
    SUM(CASE WHEN OH.ENTRY_DATE BETWEEN '2023-07-10 08:00:00' AND '2023-07-10 08:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '8 am',
    SUM(CASE WHEN OH.ENTRY_DATE BETWEEN '2023-07-10 09:00:00' AND '2023-07-10 09:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '9 am',
    SUM(CASE WHEN OH.ENTRY_DATE BETWEEN '2023-07-10 10:00:00' AND '2023-07-10 10:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '10 am',
    SUM(CASE WHEN OH.ENTRY_DATE BETWEEN '2023-07-10 11:00:00' AND '2023-07-10 11:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '11 am',
    SUM(CASE WHEN OH.ENTRY_DATE BETWEEN '2023-07-10 12:00:00' AND '2023-07-10 12:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '12 pm',
    SUM(CASE WHEN OH.ENTRY_DATE BETWEEN '2023-07-10 13:00:00' AND '2023-07-10 13:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '1 pm',
    SUM(CASE WHEN OH.ENTRY_DATE BETWEEN '2023-07-10 14:00:00' AND '2023-07-10 14:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '2 pm',
    SUM(CASE WHEN OH.ENTRY_DATE BETWEEN '2023-07-10 15:00:00' AND '2023-07-10 15:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '3 pm',
    SUM(CASE WHEN OH.ENTRY_DATE BETWEEN '2023-07-10 16:00:00' AND '2023-07-10 16:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '4 pm',
    SUM(CASE WHEN OH.ENTRY_DATE BETWEEN '2023-07-10 17:00:00' AND '2023-07-17 12:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '5 pm',
    SUM(CASE WHEN OH.ENTRY_DATE BETWEEN '2023-07-10 18:00:00' AND '2023-07-10 18:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '6 pm',
    SUM(CASE WHEN OH.ENTRY_DATE BETWEEN '2023-07-10 19:00:00' AND '2023-07-10 19:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '7 pm',
    SUM(CASE WHEN OH.ENTRY_DATE BETWEEN '2023-07-10 20:00:00' AND '2023-07-10 20:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '8 pm',
    SUM(CASE WHEN OH.ENTRY_DATE BETWEEN '2023-07-10 21:00:00' AND '2023-07-10 21:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '9 pm',
    SUM(CASE WHEN OH.ENTRY_DATE BETWEEN '2023-07-10 22:00:00' AND '2023-07-10 22:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '10 pm',
    SUM(CASE WHEN OH.ENTRY_DATE BETWEEN '2023-07-10 23:00:00' AND '2023-07-10 23:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '11 pm',
    SUM(CASE WHEN OH.ENTRY_DATE BETWEEN '2023-07-11 00:00:00' AND '2023-07-11 00:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '7/11 12 am',
    SUM(CASE WHEN OH.ENTRY_DATE BETWEEN '2023-07-11 01:00:00' AND '2023-07-11 01:59:59'
           THEN OI.QUANTITY
           ELSE 0 END) AS '7/11 1 am'
FROM ORDER_HEADER OH
INNER JOIN ORDER_PART OP ON OP.ORDER_ID = OH.ORDER_ID
INNER JOIN ORDER_ITEM OI ON OI.ORDER_ID = OP.ORDER_ID AND OI.ORDER_PART_SEQ_ID = OP.ORDER_PART_SEQ_ID AND OI.ITEM_TYPE_ENUM_ID = 'ITEMPRODUCT'
WHERE OH.ENTRY_DATE BETWEEN '2023-07-10 00:00:00' AND '2023-07-10 23:59:59'
AND OP.FACILITY_ID = 'NOG_DC_PITTSBURGH_FACILITY'
AND OI.PRODUCT_ID = '1806125';

SELECT OH.DISPLAY_ID,
       OH.PLACED_DATE,
       OP.FACILITY_ID,
       OI.OTHER_PARTY_PRODUCT_ID,
       OI.QUANTITY
FROM ORDER_HEADER OH
INNER JOIN ORDER_PART OP ON OP.ORDER_ID = OH.ORDER_ID
INNER JOIN ORDER_ITEM OI ON OI.ORDER_ID = OP.ORDER_ID AND OI.ORDER_PART_SEQ_ID = OP.ORDER_PART_SEQ_ID AND OI.ITEM_TYPE_ENUM_ID = 'ITEMPRODUCT'
WHERE OH.PLACED_DATE BETWEEN '2023-07-10 04:00:00' AND '2023-07-10 04:59:59'
AND OP.FACILITY_ID = 'NOG_DC_PITTSBURGH_FACILITY'
AND OI.PRODUCT_ID = '1806125';

/*
 check returns created during switch from RP to HR
 */
SELECT RH.DISPLAY_ID,
       RH.DISPLAY_ID,
       RH.STATUS_ID AS 'RETURN STATUS',
