/*kk_returnFromLocations*/
SELECT OP.ORDER_ID,
       OH.DISPLAY_ID,
       SRS.*,
       PA.*
FROM ORDER_PART OP
INNER JOIN ORDER_ITEM OI ON OI.ORDER_ID = OP.ORDER_ID AND OI.ORDER_PART_SEQ_ID = OP.ORDER_PART_SEQ_ID
INNER JOIN ORDER_HEADER OH ON OH.ORDER_ID = OP.ORDER_ID
INNER JOIN SHIPMENT_ITEM_SOURCE SIS ON SIS.ORDER_ID = OI.ORDER_ID AND SIS.ORDER_ITEM_SEQ_ID = OI.ORDER_ITEM_SEQ_ID
INNER JOIN SHIPMENT_ROUTE_SEGMENT SRS ON SRS.SHIPMENT_ID = SIS.SHIPMENT_ID
INNER JOIN POSTAL_ADDRESS PA ON PA.CONTACT_MECH_ID = SRS.DEST_POSTAL_CONTACT_MECH_ID
INNER JOIN RETURN_ITEM RI ON RI.ORDER_ID = OI.ORDER_ID AND RI.ORDER_ITEM_SEQ_ID = OI.ORDER_ITEM_SEQ_ID
INNER JOIN RETURN_HEADER RH ON RH.RETURN_ID = RI.RETURN_ID
WHERE OP.VENDOR_PARTY_ID = 'KK'
AND PA.COUNTRY_GEO_ID <> 'USA'
AND RH.ENTRY_DATE > '2023-01-01 00:00:00';

SELECT OH.ORDER_ID,
       OH.DISPLAY_ID,
       OH.STATUS_ID,
       OP.ORDER_PART_SEQ_ID,
       OP.STATUS_ID,
       OP.FACILITY_ID
FROM ORDER_HEADER OH
INNER JOIN ORDER_PART OP ON OP.ORDER_ID = OH.ORDER_ID
WHERE OH.PRODUCT_STORE_ID = 'IMHD_SHOPIFY'
AND OH.STATUS_ID NOT IN ('ORDERCOMPLETED','ORDERCANCELLED');


-- mantle.product.AssetServices.update#AssetAndReceipt
SELECT AR.ASSET_ID as 'assetId',
       AR.ASSET_RECEIPT_ID as 'assetReceiptId',
       AR.PRODUCT_ID as 'productId',
       'KCNY' as 'ownerPartyId',
       AR.QUANTITY_ACCEPTED as 'quantityAccepted',
       A.STATUS_ID as 'statusId',
       A.LOCATION_SEQ_ID as 'locationSeqId'
FROM ASSET_RECEIPT AR
INNER JOIN ASSET A ON A.ASSET_ID = AR.ASSET_ID
WHERE AR.SHIPMENT_ID = '6957189';

SELECT *
FROM SHIPMENT_ITEM_SOURCE
WHERE SHIPMENT_ID = '7007578';

SELECT *
FROM CARRIER_SHIPMENT_METHOD
WHERE CARRIER_PARTY_ID IN ('FEDEX','DHLEC');

SELECT EM.TO_ADDRESSES,
       COUNT(DISTINCT EM.EMAIL_MESSAGE_ID),
       EM.EMAIL_TEMPLATE_ID,
       UA.DISABLED,
       UA.TERMINATE_DATE,
       UA.PARTY_ID
FROM EMAIL_MESSAGE EM
INNER JOIN USER_ACCOUNT UA ON UA.EMAIL_ADDRESS = EM.TO_ADDRESSES
WHERE EM.STATUS_ID = 'ES_READY'
#AND UA.DISABLED = 'Y'
#AND UA.TERMINATE_DATE IS NULL
AND EM.TO_ADDRESSES LIKE ('%@alrossa.com')
#AND EM.EMAIL_TEMPLATE_ID IN ('PASSWORD_RESET')
GROUP BY EM.TO_ADDRESSES, EMAIL_TEMPLATE_ID;

/*
 find the last login and last email for parties
 */
SELECT UA.PARTY_ID,
       EM.TO_ADDRESSES,
       COUNT(DISTINCT EM.EMAIL_MESSAGE_ID) as 'emailCount',
       MAX(EM.LAST_UPDATED_STAMP) as 'lastEmail',
       UA.DISABLED,
       UA.TERMINATE_DATE,
       MAX(ULH.FROM_DATE) as 'lastLogin'
FROM USER_ACCOUNT UA
INNER JOIN USER_LOGIN_HISTORY ULH ON ULH.USER_ID = UA.USER_ID
INNER JOIN EMAIL_MESSAGE EM ON EM.TO_ADDRESSES = UA.EMAIL_ADDRESS
WHERE EM.TO_ADDRESSES NOT LIKE ('%@nogin.com')
GROUP BY EM.TO_ADDRESSES;

SELECT SMR.SYSTEM_MESSAGE_REMOTE_ID,
       SMR.DESCRIPTION,
       SMR.INTERNAL_ID,
       SMR.INTERNAL_ID_TYPE,
       SMR.INTERNAL_APP_CODE,
       SMR.REMOTE_ID,
       SMR.REMOTE_ID_TYPE,
       SMR.REMOTE_APP_CODE,
       SMR.FACILITY_ID,
       SMR.PARTY_ID
FROM SYSTEM_MESSAGE_REMOTE SMR
WHERE SMR.SYSTEM_MESSAGE_REMOTE_ID LIKE ('%peerless%') OR SMR.SYSTEM_MESSAGE_REMOTE_ID LIKE ('%6LINCOLN%');

/*
 confirm 850 is being sent to Vida SFTP
 in LogViewer, enter this into the search -> message:/KCNY_VIDA_ORD_[0-9]*_202308[0-9]*/
SELECT OH.ENTRY_DATE,
    OH.ORDER_ID,
       OH.DISPLAY_ID,
       SM.SYSTEM_MESSAGE_ID,
       SM.STATUS_ID
FROM ORDER_HEADER OH
INNER JOIN ORDER_PART OP ON OP.ORDER_ID = OH.ORDER_ID
LEFT JOIN SYSTEM_MESSAGE SM ON SM.ORDER_ID = OH.ORDER_ID
WHERE OH.ENTRY_DATE BETWEEN '2023-08-23' AND '2023-08-24'
AND OP.FACILITY_ID = 'KCNY_VIDA_FACILITY'
AND SM.DOC_SUB_TYPE = '850'
ORDER BY OH.ENTRY_DATE DESC;


SELECT SUM(CASE WHEN OI.ITEM_TYPE_ENUM_ID = 'ITEMPRODUCT'
                THEN OI.UNIT_AMOUNT
                ELSE 0 END) as 'Sales Subtotal',
    SUM(CASE WHEN OI.ITEM_TYPE_ENUM_ID = 'ITEMSALESTAX'
        THEN OI.UNIT_AMOUNT
        ELSE 0 END) as 'Sales Tax',
    SUM(CASE WHEN OI.ITEM_TYPE_ENUM_ID = 'ITEMDISCOUNT'
        THEN OI.UNIT_AMOUNT
        ELSE 0 END) as 'Discounts'
FROM ORDER_HEADER OH
INNER JOIN ORDER_PART OP ON OP.ORDER_ID = OH.ORDER_ID
INNER JOIN ORDER_ITEM OI ON OI.ORDER_ID = OP.ORDER_ID AND OI.ORDER_PART_SEQ_ID = OP.ORDER_PART_SEQ_ID
WHERE OH.PRODUCT_STORE_ID = 'BROOK_SHOPIFY'
AND OP.FACILITY_ID = 'LELOINC_BROOK_FACILITY'
AND OH.PLACED_DATE BETWEEN '2023-08-01 00:00:00' AND '2023-09-01 00:00:00';

SELECT OH.DISPLAY_ID,
       OH.STATUS_ID,
       OP.ORDER_PART_SEQ_ID,
